const files:Record<string,string>={"server/src/rooms/schema.ts": "import { ArraySchema, MapSchema, Schema, type } from '@colyseus/schema';\n\nexport class PlayerState extends Schema {\n  @type('string') id='';\n  @type('string') name='';\n  @type('number') x=2048;\n  @type('number') y=2048;\n  @type('number') angle=0;\n\n  @type('number') hp=100;\n  @type('number') armor=0;\n  @type('number') altitude=0;\n  @type('number') kills=0;\n  @type('number') damageDone=0;\n  @type('number') attackSeq=0;\n  @type('number') hitSeq=0;\n  @type('number') lastHitAngle=0;\n  @type('number') lastHitDamage=0;\n\n  @type('boolean') alive=true;\n  @type('boolean') ready=false;\n  @type('boolean') ai=false;\n  @type('boolean') host=false;\n  @type('boolean') muted=false;\n\n  @type('string') phase='lobby';\n  @type('string') primary='';\n  @type('string') secondary='';\n  @type('string') melee='fists';\n  @type('string') equipped='fists';\n  @type('string') aiState='LOBBY';\n\n  @type('number') magazine=0;\n  @type('number') pistolMagazine=0;\n  @type('number') smgMagazine=0;\n  @type('number') rifleMagazine=0;\n  @type('number') shotgunMagazine=0;\n  @type('number') smallAmmo=0;\n  @type('number') rifleAmmo=0;\n  @type('number') shells=0;\n  @type('number') bandages=0;\n  @type('number') medkits=0;\n\n  @type('string') healingKind='';\n  @type('number') healingProgress=0;\n}\n\nexport class BulletState extends Schema {\n  @type('string') id='';\n  @type('string') owner='';\n  @type('number') x=0;\n  @type('number') y=0;\n  @type('number') vx=0;\n  @type('number') vy=0;\n  @type('number') life=0;\n  @type('number') damage=0;\n}\n\nexport class LootState extends Schema {\n  @type('string') id='';\n  @type('string') kind='';\n  @type('number') x=0;\n  @type('number') y=0;\n}\n\nexport class Drop8State extends Schema {\n  @type('string') phase='LOBBY';\n  @type('string') roomCode='';\n  @type('string') hostId='';\n  @type('boolean') fillAi=true;\n  @type('string') difficulty='normal';\n  @type('string') zoneSpeed='normal';\n\n  @type({map:PlayerState}) players=new MapSchema<PlayerState>();\n  @type({map:BulletState}) bullets=new MapSchema<BulletState>();\n  @type({map:LootState}) loot=new MapSchema<LootState>();\n\n  @type('number') zoneX=2048;\n  @type('number') zoneY=2048;\n  @type('number') zoneRadius=1950;\n  @type('number') nextZoneRadius=1950;\n  @type('number') zoneTimer=30;\n  @type('number') zoneStage=0;\n\n  @type('number') planeX=0;\n  @type('number') planeY=0;\n  @type('number') planeEndX=4096;\n  @type('number') planeEndY=4096;\n  @type('number') planeProgress=0;\n\n  @type('number') aliveCount=0;\n  @type('string') winner='';\n  @type(['string']) placements=new ArraySchema<string>();\n}\n", "server/src/rooms/Drop8Room.ts": "import { Client, CloseCode, Room } from '@colyseus/core';\nimport { BulletState, Drop8State, LootState, PlayerState } from './schema.js';\nimport {\n  BUILDINGS,\n  CHAT_RADIUS,\n  FALL_START_ALTITUDE,\n  LOOT_SPAWNS,\n  MAX_PLAYERS,\n  MELEE_WEAPONS,\n  OBSTACLES,\n  PATCH_RATE_MS,\n  PLANE_DURATION,\n  PLAYER_RADIUS,\n  PLAYER_SPEED,\n  SERVER_TICK_RATE,\n  WEAPONS,\n  WORLD_SIZE,\n  circleHitsRect,\n  clamp,\n  createRoomCode,\n  distance,\n  isFiniteNumber,\n  sanitizeText,\n  type Building,\n  type Difficulty,\n  type EquippedId,\n  type LootKind,\n  type MeleeId,\n  type WeaponId,\n  type ZoneSpeed,\n} from '@drop8/shared';\n\ntype Input = { x:number; y:number; angle:number; seq:number };\ntype Point = { x:number; y:number };\ntype AiMode = 'move'|'retreat'|'hold';\ntype AiIntent = {\n  tx:number;\n  ty:number;\n  targetId:string;\n  lootId:string;\n  mode:AiMode;\n  state:string;\n  avoidSign:number;\n  stuckFor:number;\n  lastX:number;\n  lastY:number;\n  route:Point[];\n  lastSeenX:number;\n  lastSeenY:number;\n  lastSeenUntil:number;\n};\ntype HealKind = 'bandage'|'medkit';\ntype HealJob = { at:number; startedAt:number; duration:number; amount:number; kind:HealKind };\ntype ReloadJob = { at:number; weapon:WeaponId };\ntype Noise = { x:number; y:number; at:number; owner:string };\ntype JoinOptions = {\n  nickname?:unknown;\n  password?:unknown;\n  fillAi?:boolean;\n  difficulty?:Difficulty;\n  zoneSpeed?:ZoneSpeed;\n  roomPassword?:unknown;\n};\n\nconst AI_NAMES=['바람','돌멩이','야옹','쏜다','도망','파밍왕','생존봇'];\n\nexport class Drop8Room extends Room<{ state: Drop8State }> {\n  maxClients=MAX_PLAYERS;\n  state=new Drop8State();\n\n  private inputs=new Map<string,Input>();\n  private shotAt=new Map<string,number>();\n  private reloadUntil=new Map<string,ReloadJob>();\n  private healUntil=new Map<string,HealJob>();\n  private aiThinkAt=new Map<string,number>();\n  private aiIntent=new Map<string,AiIntent>();\n  private aiSwitchAt=new Map<string,number>();\n  private knockback=new Map<string,{vx:number;vy:number}>();\n  private chatAt=new Map<string,number>();\n  private noises:Noise[]=[];\n  private password='';\n  private elapsed=0;\n  private bulletSeq=0;\n  private lootSeq=0;\n  private planeStart={x:0,y:0};\n  private planeEnd={x:WORLD_SIZE,y:WORLD_SIZE};\n\n  async onCreate(options:JoinOptions) {\n    let code=createRoomCode();\n    for(let i=0;i<8 && await this.presence.get(`drop8:${code}`);i++)code=createRoomCode();\n    await this.presence.setex(`drop8:${code}`,'1',60*60*8);\n    this.roomId=code;\n    this.state.roomCode=code;\n    this.state.fillAi=options.fillAi!==false;\n    this.state.difficulty=options.difficulty??'normal';\n    this.state.zoneSpeed=options.zoneSpeed??'normal';\n    this.password=sanitizeText(options.roomPassword,32);\n    this.patchRate=PATCH_RATE_MS;\n    this.setSimulationInterval((dt)=>this.tick(dt/1000),1000/SERVER_TICK_RATE);\n\n    this.onMessage('ready',(c)=>this.ready(c));\n    this.onMessage('settings',(c,m)=>this.settings(c,m));\n    this.onMessage('start',(c)=>this.start(c));\n    this.onMessage('input',(c,m)=>this.input(c,m));\n    this.onMessage('jump',(c)=>this.jump(c));\n    this.onMessage('fire',(c)=>this.fire(c));\n    this.onMessage('melee',(c)=>this.melee(c));\n    this.onMessage('reload',(c)=>this.reload(c));\n    this.onMessage('pickup',(c)=>this.pickup(c));\n    this.onMessage('switch',(c,m)=>this.switchWeapon(c,m));\n    this.onMessage('heal',(c,m)=>this.heal(c,m));\n    this.onMessage('chat',(c,m)=>this.chat(c,m));\n    this.onMessage('rematch',(c)=>{\n      if(this.state.phase==='FINISHED'&&this.state.players.get(c.sessionId)?.host)this.resetLobby();\n    });\n  }\n\n  onAuth(_client:Client,options:JoinOptions){\n    if(this.password&&sanitizeText(options.password,32)!==this.password)throw new Error('비밀번호가 맞지 않습니다.');\n    return true;\n  }\n\n  onJoin(client:Client,options:JoinOptions){\n    const p=new PlayerState();\n    p.id=client.sessionId;\n    p.name=sanitizeText(options.nickname,16)||`유저${this.clients.length}`;\n    p.host=this.state.players.size===0;\n    this.state.players.set(client.sessionId,p);\n    if(p.host)this.state.hostId=p.id;\n    this.system(`${p.name}님이 입장했습니다.`);\n  }\n\n  async onLeave(client:Client,code:CloseCode){\n    const p=this.state.players.get(client.sessionId);\n    if(!p)return;\n    if(this.state.phase!=='LOBBY'&&code!==CloseCode.CONSENTED){\n      try{await this.allowReconnection(client,15);return;}catch{/* reconnect timeout */}\n    }\n    const wasHost=p.host;\n    this.state.players.delete(client.sessionId);\n    this.inputs.delete(client.sessionId);\n    this.cancelHeal(p);\n    this.reloadUntil.delete(p.id);\n    this.system(`${p.name}님이 퇴장했습니다.`);\n    if(wasHost){\n      const next=[...this.state.players.values()].find((v)=>!v.ai);\n      if(next){next.host=true;this.state.hostId=next.id;}\n    }\n  }\n\n  onDispose(){void this.presence.del(`drop8:${this.roomId}`);}\n\n  private system(text:string){this.broadcast('chat',{channel:'system',sender:'시스템',text,time:Date.now()});}\n\n  private ready(c:Client){\n    const p=this.state.players.get(c.sessionId);\n    if(p&&this.state.phase==='LOBBY'){\n      p.ready=!p.ready;\n      this.system(`${p.name}님이 ${p.ready?'준비했습니다.':'준비를 취소했습니다.'}`);\n    }\n  }\n\n  private settings(c:Client,m:any){\n    const p=this.state.players.get(c.sessionId);\n    if(!p?.host||this.state.phase!=='LOBBY')return;\n    if(typeof m?.fillAi==='boolean')this.state.fillAi=m.fillAi;\n    if(['easy','normal','hard'].includes(m?.difficulty))this.state.difficulty=m.difficulty;\n    if(['slow','normal','fast'].includes(m?.zoneSpeed))this.state.zoneSpeed=m.zoneSpeed;\n  }\n\n  private start(c:Client){\n    const p=this.state.players.get(c.sessionId);\n    if(!p?.host||this.state.phase!=='LOBBY')return;\n    const humans=[...this.state.players.values()].filter((v)=>!v.ai);\n    if(humans.some((v)=>!v.ready)){c.send('error','모든 실제 플레이어가 준비해야 합니다.');return;}\n    if(this.state.fillAi)this.fillAi();\n    this.beginMatch();\n  }\n\n  private fillAi(){\n    let i=1;\n    while(this.state.players.size<MAX_PLAYERS){\n      const p=new PlayerState();\n      p.id=`ai-${Date.now()}-${i}`;\n      p.name=`AI-${AI_NAMES[(i-1)%AI_NAMES.length]}`;\n      p.ai=true;\n      p.ready=true;\n      p.aiState='PLANE';\n      this.state.players.set(p.id,p);\n      i++;\n    }\n  }\n\n  private beginMatch(){\n    this.clearTransient();\n    this.elapsed=0;\n    this.state.phase='PLANE';\n    this.state.winner='';\n    this.state.placements.clear();\n    this.state.zoneX=WORLD_SIZE/2;\n    this.state.zoneY=WORLD_SIZE/2;\n    this.state.zoneRadius=1950;\n    this.state.nextZoneRadius=1950;\n    this.state.zoneTimer=30;\n    this.state.zoneStage=0;\n    this.choosePlane();\n\n    let aiIndex=0;\n    for(const p of this.state.players.values()){\n      p.hp=100;\n      p.armor=0;\n      p.alive=true;\n      p.kills=0;\n      p.damageDone=0;\n      p.attackSeq=0;\n      p.hitSeq=0;\n      p.lastHitAngle=0;\n      p.lastHitDamage=0;\n      p.phase='plane';\n      p.altitude=FALL_START_ALTITUDE;\n      p.primary='';\n      p.secondary='';\n      p.melee='fists';\n      p.equipped='fists';\n      p.aiState=p.ai?'PLANE':'';\n      p.magazine=0;\n      p.pistolMagazine=0;\n      p.smgMagazine=0;\n      p.rifleMagazine=0;\n      p.shotgunMagazine=0;\n      p.smallAmmo=0;\n      p.rifleAmmo=0;\n      p.shells=0;\n      p.bandages=0;\n      p.medkits=0;\n      p.healingKind='';\n      p.healingProgress=0;\n      p.x=this.planeStart.x;\n      p.y=this.planeStart.y;\n      if(p.ai){\n        this.aiThinkAt.set(p.id,3+aiIndex++*1.7);\n        this.aiIntent.set(p.id,this.newAiIntent(p));\n      }\n    }\n    this.state.aliveCount=this.state.players.size;\n    this.spawnLoot();\n    this.system('비행기가 출발했습니다. Space로 낙하하세요.');\n  }\n\n  private newAiIntent(p:PlayerState):AiIntent{\n    return {\n      tx:p.x,ty:p.y,targetId:'',lootId:'',mode:'move',state:'PATROL',\n      avoidSign:Math.random()<.5?-1:1,stuckFor:0,lastX:p.x,lastY:p.y,\n      route:[],lastSeenX:p.x,lastSeenY:p.y,lastSeenUntil:0,\n    };\n  }\n\n  private choosePlane(){\n    const horizontal=Math.random()<.5;\n    if(horizontal){\n      const y=400+Math.random()*(WORLD_SIZE-800);\n      this.planeStart={x:0,y};\n      this.planeEnd={x:WORLD_SIZE,y:WORLD_SIZE-y};\n    }else{\n      const x=400+Math.random()*(WORLD_SIZE-800);\n      this.planeStart={x,y:0};\n      this.planeEnd={x:WORLD_SIZE-x,y:WORLD_SIZE};\n    }\n    this.state.planeX=this.planeStart.x;\n    this.state.planeY=this.planeStart.y;\n    this.state.planeEndX=this.planeEnd.x;\n    this.state.planeEndY=this.planeEnd.y;\n    this.state.planeProgress=0;\n  }\n\n  private spawnLoot(){\n    this.state.loot.clear();\n    const weighted:LootKind[]=[\n      'pistol','pistol','smg','rifle','shotgun','small_ammo','small_ammo','rifle_ammo','shells',\n      'vest','bandage','bandage','medkit','bat','pan','pipe','knife',\n    ];\n    for(const spawn of LOOT_SPAWNS){\n      const l=new LootState();\n      l.id=`loot-${++this.lootSeq}`;\n      l.kind=weighted[Math.floor(Math.random()*weighted.length)]!;\n      const pos=this.findLootPosition(spawn.x,spawn.y);\n      l.x=pos.x;\n      l.y=pos.y;\n      this.state.loot.set(l.id,l);\n    }\n  }\n\n  private findLootPosition(baseX:number,baseY:number){\n    for(let i=0;i<18;i++){\n      const radius=i<4?70:70+i*16;\n      const angle=i*2.399963;\n      const x=clamp(baseX+Math.cos(angle)*radius*(i===0?0:1),40,WORLD_SIZE-40);\n      const y=clamp(baseY+Math.sin(angle)*radius*(i===0?0:1),40,WORLD_SIZE-40);\n      if(!OBSTACLES.some((r)=>circleHitsRect(x,y,14,r)))return{x,y};\n    }\n    return{x:clamp(baseX,40,WORLD_SIZE-40),y:clamp(baseY,40,WORLD_SIZE-40)};\n  }\n\n  private clearTransient(){\n    this.state.bullets.clear();\n    this.state.loot.clear();\n    this.inputs.clear();\n    this.shotAt.clear();\n    this.reloadUntil.clear();\n    this.healUntil.clear();\n    this.aiIntent.clear();\n    this.aiSwitchAt.clear();\n    this.knockback.clear();\n    this.noises=[];\n  }\n\n  private input(c:Client,m:any){\n    const p=this.state.players.get(c.sessionId);\n    if(!p||p.ai||!p.alive)return;\n    if(!isFiniteNumber(m?.x)||!isFiniteNumber(m?.y)||!isFiniteNumber(m?.angle))return;\n    this.inputs.set(p.id,{x:clamp(m.x,-1,1),y:clamp(m.y,-1,1),angle:m.angle,seq:Number(m.seq)||0});\n  }\n\n  private jump(c:Client){const p=this.state.players.get(c.sessionId);if(p?.phase==='plane')this.doJump(p);}\n\n  private doJump(p:PlayerState){\n    p.phase='falling';\n    p.aiState=p.ai?'FALLING':'';\n    p.x=this.state.planeX;\n    p.y=this.state.planeY;\n    p.altitude=FALL_START_ALTITUDE;\n    if(this.state.phase==='PLANE')this.state.phase='DROP';\n  }\n\n  private fire(c:Client){const p=this.state.players.get(c.sessionId);if(p)this.firePlayer(p);}\n\n  private firePlayer(p:PlayerState){\n    if(!p.alive||p.phase!=='landed')return;\n    if(this.healUntil.has(p.id)){this.cancelHeal(p);return;}\n    if(this.reloadUntil.has(p.id))return;\n    const id=p.equipped as WeaponId;\n    const w=WEAPONS[id];\n    if(!w||w.id==='fists')return;\n    const magazine=this.getWeaponMagazine(p,id);\n    if(magazine<=0)return;\n    const now=this.now();\n    if(now-(this.shotAt.get(p.id)??-99)<w.fireInterval)return;\n    this.shotAt.set(p.id,now);\n    p.attackSeq++;\n    this.setWeaponMagazine(p,id,magazine-1);\n    this.noises.push({x:p.x,y:p.y,at:now,owner:p.id});\n    for(let i=0;i<w.pellets;i++){\n      const a=p.angle+(Math.random()*2-1)*w.spread;\n      const b=new BulletState();\n      b.id=`b-${++this.bulletSeq}`;\n      b.owner=p.id;\n      b.x=p.x+Math.cos(a)*28;\n      b.y=p.y+Math.sin(a)*28;\n      b.vx=Math.cos(a)*w.projectileSpeed;\n      b.vy=Math.sin(a)*w.projectileSpeed;\n      b.life=w.range/w.projectileSpeed;\n      b.damage=w.damage;\n      this.state.bullets.set(b.id,b);\n    }\n  }\n\n  private melee(c:Client){const p=this.state.players.get(c.sessionId);if(p)this.meleePlayer(p);}\n\n  private meleePlayer(p:PlayerState){\n    if(!p.alive||p.phase!=='landed')return;\n    if(this.healUntil.has(p.id)){this.cancelHeal(p);return;}\n    const melee=p.equipped==='fists'\n      ?{name:'주먹',damage:WEAPONS.fists.damage,fireInterval:WEAPONS.fists.fireInterval,range:WEAPONS.fists.range,arc:1.1}\n      :MELEE_WEAPONS[p.equipped as MeleeId];\n    if(!melee)return;\n    const now=this.now();\n    if(now-(this.shotAt.get(p.id)??-99)<melee.fireInterval)return;\n    this.shotAt.set(p.id,now);\n    p.attackSeq++;\n    let target:PlayerState|undefined;\n    let best=melee.range;\n    for(const other of this.state.players.values()){\n      if(!other.alive||other.id===p.id||other.phase!=='landed')continue;\n      const d=distance(p.x,p.y,other.x,other.y);\n      if(d<best&&Math.abs(this.angleDiff(Math.atan2(other.y-p.y,other.x-p.x),p.angle))<melee.arc){target=other;best=d;}\n    }\n    if(target)this.damage(target,melee.damage,p.id,p.equipped==='fists'?'주먹':melee.name);\n  }\n\n  private reload(c:Client){\n    const p=this.state.players.get(c.sessionId);\n    if(!p)return;\n    if(this.healUntil.has(p.id)){this.cancelHeal(p);return;}\n    this.beginReload(p);\n  }\n\n  private beginReload(p:PlayerState,weaponId:WeaponId=p.equipped as WeaponId){\n    if(this.reloadUntil.has(p.id))return false;\n    const w=WEAPONS[weaponId];\n    if(!w||w.id==='fists')return false;\n    const magazine=this.getWeaponMagazine(p,weaponId);\n    if(magazine>=w.magazine||this.getAmmo(p,w.ammoType)<=0)return false;\n    this.reloadUntil.set(p.id,{at:this.now()+w.reloadSeconds,weapon:weaponId});\n    if(p.ai)p.aiState='RELOAD';\n    return true;\n  }\n\n  private pickup(c:Client){\n    const p=this.state.players.get(c.sessionId);\n    if(!p||p.phase!=='landed'||!p.alive)return;\n    if(this.healUntil.has(p.id))this.cancelHeal(p);\n    let pick:LootState|undefined;\n    let best=72;\n    for(const l of this.state.loot.values()){\n      const d=distance(p.x,p.y,l.x,l.y);\n      if(d<best){best=d;pick=l;}\n    }\n    if(!pick)return;\n    this.applyLoot(p,pick.kind as LootKind);\n    this.state.loot.delete(pick.id);\n  }\n\n  private applyLoot(p:PlayerState,k:LootKind){\n    if(k in WEAPONS&&k!=='fists'){\n      const id=k as WeaponId;\n      const w=WEAPONS[id]!;\n      if(w.slot==='primary')p.primary=id;\n      else p.secondary=id;\n      if(this.getWeaponMagazine(p,id)<=0)this.setWeaponMagazine(p,id,w.magazine,false);\n      if(w.ammoType==='small')p.smallAmmo+=w.magazine*2;\n      if(w.ammoType==='rifle')p.rifleAmmo+=w.magazine*2;\n      if(w.ammoType==='shells')p.shells+=w.magazine*2;\n      this.setEquipped(p,id,true);\n      return;\n    }\n    if(k in MELEE_WEAPONS){p.melee=k;this.setEquipped(p,k as MeleeId,true);return;}\n    if(k==='small_ammo')p.smallAmmo+=30;\n    else if(k==='rifle_ammo')p.rifleAmmo+=24;\n    else if(k==='shells')p.shells+=12;\n    else if(k==='vest')p.armor=Math.max(p.armor,100);\n    else if(k==='bandage')p.bandages=Math.min(5,p.bandages+1);\n    else if(k==='medkit')p.medkits=Math.min(2,p.medkits+1);\n  }\n\n  private switchWeapon(c:Client,m:any){\n    const p=this.state.players.get(c.sessionId);\n    if(!p)return;\n    const slot=Number(m?.slot);\n    const id=(slot===1?p.primary:slot===2?p.secondary:p.melee||'fists') as EquippedId;\n    if(!id||(!(id in WEAPONS)&&!(id in MELEE_WEAPONS)))return;\n    this.cancelHeal(p);\n    this.setEquipped(p,id,true);\n  }\n\n  private setEquipped(p:PlayerState,id:EquippedId,force=false){\n    if(p.equipped===id){this.syncMagazine(p);return;}\n    if(!force&&p.ai&&this.now()<(this.aiSwitchAt.get(p.id)??0))return;\n    p.equipped=id;\n    this.reloadUntil.delete(p.id);\n    this.syncMagazine(p);\n    if(p.ai)this.aiSwitchAt.set(p.id,this.now()+.8);\n  }\n\n  private heal(c:Client,m:any){\n    const p=this.state.players.get(c.sessionId);\n    if(!p)return;\n    const requested=m?.kind==='medkit'?'medkit':m?.kind==='bandage'?'bandage':'auto';\n    if(!this.beginHeal(p,requested))c.send('error',p.hp>=100?'이미 체력이 가득합니다.':'사용할 회복 아이템이 없습니다.');\n  }\n\n  private beginHeal(p:PlayerState,requested:'auto'|HealKind='auto'){\n    if(!p.alive||p.phase!=='landed'||p.hp>=100||this.healUntil.has(p.id))return false;\n    const missing=100-p.hp;\n    let kind:HealKind|''='';\n    if(requested==='medkit'&&p.medkits>0)kind='medkit';\n    else if(requested==='bandage'&&p.bandages>0)kind='bandage';\n    else if(requested==='auto'){\n      if(p.medkits>0&&(missing>25||p.bandages<=0))kind='medkit';\n      else if(p.bandages>0)kind='bandage';\n      else if(p.medkits>0)kind='medkit';\n    }\n    if(!kind)return false;\n    const duration=kind==='medkit'?4:2;\n    const amount=kind==='medkit'?60:25;\n    const startedAt=this.now();\n    this.reloadUntil.delete(p.id);\n    this.healUntil.set(p.id,{at:startedAt+duration,startedAt,duration,amount,kind});\n    p.healingKind=kind;\n    p.healingProgress=0;\n    if(p.ai)p.aiState='HEAL';\n    return true;\n  }\n\n  private cancelHeal(p:PlayerState){\n    if(!this.healUntil.delete(p.id)&&!p.healingKind)return;\n    p.healingKind='';\n    p.healingProgress=0;\n  }\n\n  private chat(c:Client,m:any){\n    const p=this.state.players.get(c.sessionId);\n    if(!p||p.muted)return;\n    const text=sanitizeText(m?.text,80);\n    if(!text)return;\n    const now=Date.now();\n    if(now-(this.chatAt.get(p.id)??0)<650)return;\n    this.chatAt.set(p.id,now);\n    if(this.state.phase==='LOBBY'){\n      this.broadcast('chat',{channel:'lobby',sender:p.name,text,time:now});\n      return;\n    }\n    if(!p.alive){\n      for(const cl of this.clients){\n        const q=this.state.players.get(cl.sessionId);\n        if(q&&!q.alive)cl.send('chat',{channel:'spectator',sender:p.name,text,time:now});\n      }\n      return;\n    }\n    for(const cl of this.clients){\n      const q=this.state.players.get(cl.sessionId);\n      if(q?.alive&&distance(p.x,p.y,q.x,q.y)<=CHAT_RADIUS)cl.send('chat',{channel:'nearby',sender:p.name,text,time:now,playerId:p.id});\n    }\n  }\n\n  private tick(dt:number){\n    if(this.state.phase==='LOBBY'||this.state.phase==='FINISHED')return;\n    this.elapsed+=dt;\n    this.updatePlane(dt);\n    this.updatePlayers(dt);\n    this.updateReloads();\n    this.updateHeals();\n    this.updateBullets(dt);\n    this.updateZone(dt);\n    this.updateAi(dt);\n    this.noises=this.noises.filter((n)=>this.now()-n.at<3);\n    this.finishCheck();\n  }\n\n  private updatePlane(_dt:number){\n    if(!['PLANE','DROP'].includes(this.state.phase))return;\n    this.state.planeProgress=clamp(this.elapsed/PLANE_DURATION,0,1);\n    this.state.planeX=this.planeStart.x+(this.planeEnd.x-this.planeStart.x)*this.state.planeProgress;\n    this.state.planeY=this.planeStart.y+(this.planeEnd.y-this.planeStart.y)*this.state.planeProgress;\n    for(const p of this.state.players.values()){\n      if(p.phase==='plane'){\n        p.x=this.state.planeX;\n        p.y=this.state.planeY;\n        if(p.ai&&this.elapsed>=(this.aiThinkAt.get(p.id)??8))this.doJump(p);\n        if(this.state.planeProgress>=1)this.doJump(p);\n      }\n    }\n  }\n\n  private updatePlayers(dt:number){\n    for(const p of this.state.players.values()){\n      if(!p.alive)continue;\n      const input=this.inputs.get(p.id)??{x:0,y:0,angle:p.angle,seq:0};\n      if(!p.ai)p.angle=input.angle;\n      if(p.phase==='falling'||p.phase==='parachute'){\n        const parachute=p.altitude<300;\n        p.phase=parachute?'parachute':'falling';\n        if(p.ai)p.aiState=parachute?'PARACHUTE':'FALLING';\n        const speed=parachute?145:260;\n        const driftX=p.ai?Math.cos(p.angle)*.55:input.x;\n        const driftY=p.ai?Math.sin(p.angle)*.55:input.y;\n        this.tryMove(p,driftX*speed*dt,driftY*speed*dt);\n        p.altitude=Math.max(0,p.altitude-(parachute?120:260)*dt);\n        if(p.altitude<=0){p.phase='landed';if(p.ai)p.aiState='SEEK_WEAPON';this.system(`${p.name} 착지`);}\n        continue;\n      }\n      if(p.phase!=='landed')continue;\n\n      const kick=this.knockback.get(p.id);\n      if(kick){\n        this.tryMove(p,kick.vx*dt,kick.vy*dt);\n        const damping=Math.pow(.035,dt);\n        kick.vx*=damping;\n        kick.vy*=damping;\n        if(Math.hypot(kick.vx,kick.vy)<8)this.knockback.delete(p.id);\n      }\n\n      if(p.ai)continue;\n      if(this.healUntil.has(p.id)&&Math.hypot(input.x,input.y)>.08)this.cancelHeal(p);\n      if(this.healUntil.has(p.id))continue;\n      const ranged=WEAPONS[(p.equipped||'fists') as WeaponId];\n      const melee=MELEE_WEAPONS[p.equipped as MeleeId];\n      const moveMultiplier=ranged?.moveMultiplier??melee?.moveMultiplier??1;\n      this.tryMove(p,input.x*PLAYER_SPEED*moveMultiplier*dt,input.y*PLAYER_SPEED*moveMultiplier*dt);\n    }\n  }\n\n  private tryMove(p:PlayerState,dx:number,dy:number){\n    const beforeX=p.x;\n    const beforeY=p.y;\n    const len=Math.hypot(dx,dy);\n    if(len>18){dx=dx/len*18;dy=dy/len*18;}\n    const nx=clamp(p.x+dx,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS);\n    const ny=clamp(p.y+dy,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS);\n    if(!OBSTACLES.some((r)=>circleHitsRect(nx,p.y,PLAYER_RADIUS,r)))p.x=nx;\n    if(!OBSTACLES.some((r)=>circleHitsRect(p.x,ny,PLAYER_RADIUS,r)))p.y=ny;\n    return Math.hypot(p.x-beforeX,p.y-beforeY)>.05;\n  }\n\n  private updateReloads(){\n    const now=this.now();\n    for(const [id,job] of [...this.reloadUntil]){\n      if(now<job.at)continue;\n      const p=this.state.players.get(id);\n      if(p){\n        const w=WEAPONS[job.weapon]!;\n        const current=this.getWeaponMagazine(p,job.weapon);\n        const need=w.magazine-current;\n        const reserve=this.getAmmo(p,w.ammoType);\n        const load=Math.min(need,reserve);\n        this.setWeaponMagazine(p,job.weapon,current+load,false);\n        this.setAmmo(p,w.ammoType,reserve-load);\n        if(p.ai)p.aiState='ENGAGE';\n      }\n      this.reloadUntil.delete(id);\n    }\n  }\n\n  private updateHeals(){\n    const now=this.now();\n    for(const [id,h] of [...this.healUntil]){\n      const p=this.state.players.get(id);\n      if(!p?.alive){if(p)this.cancelHeal(p);else this.healUntil.delete(id);continue;}\n      p.healingProgress=clamp((now-h.startedAt)/h.duration,0,1);\n      if(now<h.at)continue;\n      const available=h.kind==='medkit'?p.medkits:p.bandages;\n      if(available>0){\n        if(h.kind==='medkit')p.medkits--;\n        else p.bandages--;\n        p.hp=Math.min(100,p.hp+h.amount);\n      }\n      this.cancelHeal(p);\n      if(p.ai)p.aiState='PATROL';\n    }\n  }\n\n  private updateBullets(dt:number){\n    for(const [id,b] of [...this.state.bullets]){\n      const ox=b.x;\n      const oy=b.y;\n      b.x+=b.vx*dt;\n      b.y+=b.vy*dt;\n      b.life-=dt;\n      if(\n        b.life<=0||b.x<0||b.y<0||b.x>WORLD_SIZE||b.y>WORLD_SIZE||\n        OBSTACLES.some((r)=>this.segmentRect(ox,oy,b.x,b.y,r))\n      ){\n        this.state.bullets.delete(id);\n        continue;\n      }\n      for(const p of this.state.players.values()){\n        if(!p.alive||p.id===b.owner||p.phase!=='landed')continue;\n        if(distance(b.x,b.y,p.x,p.y)<PLAYER_RADIUS+5){\n          this.damage(p,b.damage,b.owner,'총기');\n          this.state.bullets.delete(id);\n          break;\n        }\n      }\n    }\n  }\n\n  private updateZone(dt:number){\n    const landed=[...this.state.players.values()].some((p)=>p.phase==='landed');\n    if(!landed)return;\n    const mult=this.state.zoneSpeed==='fast'?1.35:this.state.zoneSpeed==='slow'?.8:1;\n    this.state.zoneTimer-=dt*mult;\n    if(this.state.zoneTimer<=0&&this.state.zoneStage<6){\n      this.state.zoneStage++;\n      this.state.nextZoneRadius=Math.max(120,this.state.zoneRadius*(this.state.zoneStage===1?.68:.72));\n      this.state.zoneTimer=this.state.zoneStage===1?52:42;\n      this.state.zoneX=clamp(this.state.zoneX+(Math.random()-.5)*(this.state.zoneRadius-this.state.nextZoneRadius),this.state.nextZoneRadius,WORLD_SIZE-this.state.nextZoneRadius);\n      this.state.zoneY=clamp(this.state.zoneY+(Math.random()-.5)*(this.state.zoneRadius-this.state.nextZoneRadius),this.state.nextZoneRadius,WORLD_SIZE-this.state.nextZoneRadius);\n    }\n    if(this.state.nextZoneRadius<this.state.zoneRadius)this.state.zoneRadius=Math.max(this.state.nextZoneRadius,this.state.zoneRadius-dt*(28+this.state.zoneStage*16)*mult);\n    for(const p of this.state.players.values()){\n      if(p.alive&&p.phase==='landed'&&distance(p.x,p.y,this.state.zoneX,this.state.zoneY)>this.state.zoneRadius)this.damage(p,(2+this.state.zoneStage*1.8)*dt,'','자기장');\n    }\n  }\n\n  private updateAi(dt:number){\n    const now=this.now();\n    for(const p of this.state.players.values()){\n      if(!p.ai||!p.alive||p.phase!=='landed')continue;\n      let intent=this.aiIntent.get(p.id);\n      if(!intent){intent=this.newAiIntent(p);this.aiIntent.set(p.id,intent);}\n      if(now>=(this.aiThinkAt.get(p.id)??0)){\n        this.aiThinkAt.set(p.id,now+(this.state.difficulty==='hard'?.14:this.state.difficulty==='easy'?.34:.22));\n        this.planAi(p,intent);\n      }\n      this.runAi(p,intent,dt);\n    }\n  }\n\n  private planAi(p:PlayerState,intent:AiIntent){\n    const now=this.now();\n    intent.targetId='';\n    intent.lootId='';\n    intent.mode='move';\n\n    const outside=distance(p.x,p.y,this.state.zoneX,this.state.zoneY)>this.state.zoneRadius-180;\n    if(outside){\n      this.cancelHeal(p);\n      p.aiState='ZONE_ESCAPE';\n      intent.state='ZONE_ESCAPE';\n      this.setAiDestination(p,intent,this.state.zoneX,this.state.zoneY);\n      return;\n    }\n\n    const target=this.findVisibleTarget(p,950);\n    const targetDistance=target?distance(p.x,p.y,target.x,target.y):Number.POSITIVE_INFINITY;\n    const danger=target&&targetDistance<430;\n\n    if(this.healUntil.has(p.id)){\n      p.aiState='HEAL';\n      intent.state='HEAL';\n      intent.mode='hold';\n      return;\n    }\n\n    if(p.hp<=55&&(p.bandages>0||p.medkits>0)&&!danger){\n      if(this.beginHeal(p,'auto')){\n        intent.state='HEAL';\n        intent.mode='hold';\n        return;\n      }\n    }\n\n    if(target){\n      intent.targetId=target.id;\n      intent.lastSeenX=target.x;\n      intent.lastSeenY=target.y;\n      intent.lastSeenUntil=now+2;\n      this.chooseAiWeapon(p,targetDistance);\n      const weapon=WEAPONS[p.equipped as WeaponId];\n      if(weapon&&weapon.id!=='fists'&&this.getWeaponMagazine(p,weapon.id)<=0){\n        if(this.getAmmo(p,weapon.ammoType)>0){\n          this.beginReload(p,weapon.id);\n          p.aiState='RELOAD';\n          intent.state='RELOAD';\n          intent.mode='retreat';\n          this.setAiDestination(p,intent,p.x-(target.x-p.x),p.y-(target.y-p.y));\n          return;\n        }\n        this.chooseAiWeapon(p,targetDistance,true);\n      }\n      p.aiState=p.hp<30?'RETREAT':'ENGAGE';\n      intent.state=p.aiState;\n      const desired=this.desiredRange(p.equipped as EquippedId);\n      if(p.hp<30||targetDistance<desired*.48){\n        intent.mode='retreat';\n        this.setAiDestination(p,intent,p.x-(target.x-p.x),p.y-(target.y-p.y));\n      }else if(targetDistance>desired*1.12){\n        intent.mode='move';\n        this.setAiDestination(p,intent,target.x,target.y);\n      }else{\n        intent.mode='hold';\n        intent.route=[];\n        intent.tx=target.x;\n        intent.ty=target.y;\n      }\n      return;\n    }\n\n    if(intent.lastSeenUntil>now){\n      p.aiState='REPOSITION';\n      intent.state='REPOSITION';\n      this.setAiDestination(p,intent,intent.lastSeenX,intent.lastSeenY);\n      return;\n    }\n\n    const noise=this.findRecentNoise(p);\n    if(noise){\n      p.aiState='INVESTIGATE';\n      intent.state='INVESTIGATE';\n      this.setAiDestination(p,intent,noise.x,noise.y);\n      return;\n    }\n\n    this.chooseAiWeapon(p);\n    const current=WEAPONS[p.equipped as WeaponId];\n    if(current&&current.id!=='fists'&&this.getWeaponMagazine(p,current.id)<=0&&this.getAmmo(p,current.ammoType)>0){\n      this.beginReload(p,current.id);\n    }\n\n    const loot=this.findBestLoot(p);\n    if(loot){\n      intent.lootId=loot.id;\n      p.aiState=this.aiLootState(loot.kind as LootKind);\n      intent.state=p.aiState;\n      this.setAiDestination(p,intent,loot.x,loot.y);\n      return;\n    }\n\n    p.aiState='PATROL';\n    intent.state='PATROL';\n    this.setAiDestination(\n      p,\n      intent,\n      this.state.zoneX+(Math.random()-.5)*Math.min(650,this.state.zoneRadius*.45),\n      this.state.zoneY+(Math.random()-.5)*Math.min(650,this.state.zoneRadius*.45),\n    );\n  }\n\n  private runAi(p:PlayerState,intent:AiIntent,dt:number){\n    if(this.healUntil.has(p.id))return;\n    const target=intent.targetId?this.state.players.get(intent.targetId):undefined;\n    if(target?.alive){\n      const clear=!OBSTACLES.some((r)=>this.segmentRect(p.x,p.y,target.x,target.y,r));\n      if(clear){\n        const d=distance(p.x,p.y,target.x,target.y);\n        p.angle=Math.atan2(target.y-p.y,target.x-p.x);\n        this.chooseAiWeapon(p,d);\n        if(p.equipped==='fists'||p.equipped in MELEE_WEAPONS){\n          const melee=p.equipped==='fists'?WEAPONS.fists:MELEE_WEAPONS[p.equipped as MeleeId];\n          if(d<=melee.range+4)this.meleePlayer(p);\n        }else{\n          const weapon=WEAPONS[p.equipped as WeaponId]!;\n          if(this.getWeaponMagazine(p,weapon.id)>0)this.firePlayer(p);\n          else if(this.getAmmo(p,weapon.ammoType)>0)this.beginReload(p,weapon.id);\n        }\n      }\n    }\n\n    const loot=intent.lootId?this.state.loot.get(intent.lootId):undefined;\n    if(loot&&distance(p.x,p.y,loot.x,loot.y)<72){\n      if(this.aiLootScore(p,loot.kind as LootKind)>0){\n        this.applyLoot(p,loot.kind as LootKind);\n        this.state.loot.delete(loot.id);\n      }\n      intent.lootId='';\n      intent.route=[];\n      this.aiThinkAt.set(p.id,0);\n    }\n\n    if(intent.mode==='hold'){\n      if(target){\n        const side=p.angle+Math.PI/2*intent.avoidSign;\n        this.tryMove(p,Math.cos(side)*72*dt,Math.sin(side)*72*dt);\n      }\n      return;\n    }\n\n    this.advanceAiRoute(p,intent);\n    const waypoint=intent.route[0]??{x:intent.tx,y:intent.ty};\n    let angle=Math.atan2(waypoint.y-p.y,waypoint.x-p.x);\n    if(intent.mode==='retreat'&&target)angle=Math.atan2(p.y-target.y,p.x-target.x);\n    if(!target)p.angle=angle;\n    const speed=this.state.difficulty==='hard'?235:this.state.difficulty==='easy'?175:205;\n    let moved=this.tryMove(p,Math.cos(angle)*speed*dt,Math.sin(angle)*speed*dt);\n    if(!moved){\n      const side=angle+intent.avoidSign*Math.PI/2;\n      moved=this.tryMove(p,Math.cos(side)*speed*.9*dt,Math.sin(side)*speed*.9*dt);\n      if(!moved){\n        intent.avoidSign*=-1;\n        const other=angle+intent.avoidSign*Math.PI/2;\n        this.tryMove(p,Math.cos(other)*speed*.85*dt,Math.sin(other)*speed*.85*dt);\n      }\n    }\n\n    const progress=distance(p.x,p.y,intent.lastX,intent.lastY);\n    intent.stuckFor=progress<1?intent.stuckFor+dt:Math.max(0,intent.stuckFor-dt*2);\n    if(intent.stuckFor>.65){\n      intent.avoidSign*=-1;\n      const detour={\n        x:clamp(p.x+Math.cos(angle+intent.avoidSign*Math.PI/2)*220,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS),\n        y:clamp(p.y+Math.sin(angle+intent.avoidSign*Math.PI/2)*220,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS),\n      };\n      intent.route.unshift(detour);\n      intent.stuckFor=0;\n    }\n    intent.lastX=p.x;\n    intent.lastY=p.y;\n  }\n\n  private findVisibleTarget(p:PlayerState,maxDistance:number){\n    let target:PlayerState|undefined;\n    let best=maxDistance;\n    for(const q of this.state.players.values()){\n      if(q.id===p.id||!q.alive||q.phase!=='landed')continue;\n      const d=distance(p.x,p.y,q.x,q.y);\n      if(d>=best)continue;\n      if(OBSTACLES.some((r)=>this.segmentRect(p.x,p.y,q.x,q.y,r)))continue;\n      best=d;\n      target=q;\n    }\n    return target;\n  }\n\n  private findRecentNoise(p:PlayerState){\n    const now=this.now();\n    let selected:Noise|undefined;\n    let best=900;\n    for(const noise of this.noises){\n      if(noise.owner===p.id||now-noise.at>2.5)continue;\n      const d=distance(p.x,p.y,noise.x,noise.y);\n      if(d<best){best=d;selected=noise;}\n    }\n    return selected;\n  }\n\n  private findBestLoot(p:PlayerState){\n    let selected:LootState|undefined;\n    let best=0;\n    for(const l of this.state.loot.values()){\n      const d=distance(p.x,p.y,l.x,l.y);\n      if(d>950)continue;\n      const score=this.aiLootScore(p,l.kind as LootKind)-d*.035;\n      if(score>best){best=score;selected=l;}\n    }\n    return selected;\n  }\n\n  private aiLootScore(p:PlayerState,k:LootKind){\n    if(k in WEAPONS&&k!=='fists'){\n      const id=k as WeaponId;\n      const w=WEAPONS[id];\n      const incoming=this.weaponBaseScore(id);\n      const held=w.slot==='primary'&&p.primary?this.weaponBaseScore(p.primary as WeaponId):w.slot==='secondary'&&p.secondary?this.weaponBaseScore(p.secondary as WeaponId):0;\n      return incoming>held+4?95+(incoming-held):incoming===held?8:0;\n    }\n    if(k in MELEE_WEAPONS){\n      const held=p.melee==='fists'?0:this.meleeScore(p.melee as MeleeId);\n      const incoming=this.meleeScore(k as MeleeId);\n      return incoming>held?42+(incoming-held):0;\n    }\n    if(k==='small_ammo')return(p.secondary==='pistol'||p.primary==='smg')&&p.smallAmmo<90?62-p.smallAmmo*.25:0;\n    if(k==='rifle_ammo')return p.primary==='rifle'&&p.rifleAmmo<72?66-p.rifleAmmo*.35:0;\n    if(k==='shells')return p.primary==='shotgun'&&p.shells<28?64-p.shells*.8:0;\n    if(k==='vest')return p.armor<70?72-p.armor*.4:0;\n    if(k==='bandage')return p.bandages<3?55-p.bandages*12:0;\n    if(k==='medkit')return p.medkits<2?68-p.medkits*20:0;\n    return 0;\n  }\n\n  private aiLootState(k:LootKind){\n    if(k in WEAPONS)return'SEEK_WEAPON';\n    if(k==='small_ammo'||k==='rifle_ammo'||k==='shells')return'SEEK_AMMO';\n    if(k==='vest')return'SEEK_ARMOR';\n    if(k==='bandage'||k==='medkit')return'SEEK_HEAL';\n    return'LOOT';\n  }\n\n  private chooseAiWeapon(p:PlayerState,targetDistance=350,force=false){\n    const candidates:EquippedId[]=['fists'];\n    if(p.melee&&p.melee!=='fists')candidates.push(p.melee as MeleeId);\n    if(p.secondary)candidates.push(p.secondary as WeaponId);\n    if(p.primary)candidates.push(p.primary as WeaponId);\n    let bestId:EquippedId='fists';\n    let best=-999;\n    for(const id of candidates){\n      const score=this.aiWeaponScore(p,id,targetDistance);\n      if(score>best){best=score;bestId=id;}\n    }\n    const currentScore=this.aiWeaponScore(p,p.equipped as EquippedId,targetDistance);\n    const currentUsable=currentScore>-500;\n    if(force||!currentUsable||best>currentScore+7)this.setEquipped(p,bestId,force||!currentUsable);\n    else this.syncMagazine(p);\n  }\n\n  private aiWeaponScore(p:PlayerState,id:EquippedId,d:number){\n    if(id==='fists')return d<=70?35:-700;\n    if(id in MELEE_WEAPONS){const melee=MELEE_WEAPONS[id as MeleeId]!;return d<=melee.range+18?58+this.meleeScore(id as MeleeId):-650;}\n    const w=WEAPONS[id as WeaponId];\n    if(!w)return-999;\n    const ammo=this.getWeaponMagazine(p,w.id)+this.getAmmo(p,w.ammoType);\n    if(ammo<=0)return-800;\n    let score=this.weaponBaseScore(w.id);\n    if(w.id==='shotgun')score+=d<220?55:d>500?-65:8;\n    if(w.id==='smg')score+=d>=90&&d<=420?38:d>650?-35:5;\n    if(w.id==='rifle')score+=d>260?44:d<120?-28:12;\n    if(w.id==='pistol')score+=d>650?12:4;\n    if(this.getWeaponMagazine(p,w.id)<=0)score-=18;\n    return score;\n  }\n\n  private desiredRange(id:EquippedId):number{\n    if(id==='fists')return 58;\n    if(id in MELEE_WEAPONS)return MELEE_WEAPONS[id as MeleeId]!.range*.82;\n    if(id==='shotgun')return 175;\n    if(id==='smg')return 260;\n    if(id==='rifle')return 410;\n    return 330;\n  }\n\n  private weaponBaseScore(id:WeaponId):number{return id==='rifle'?90:id==='smg'?82:id==='shotgun'?78:id==='pistol'?52:0;}\n  private meleeScore(id:MeleeId):number{return id==='pan'?30:id==='bat'?27:id==='pipe'?24:19;}\n\n  private setAiDestination(p:PlayerState,intent:AiIntent,x:number,y:number){\n    intent.tx=clamp(x,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS);\n    intent.ty=clamp(y,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS);\n    intent.route=this.buildRoute(p.x,p.y,intent.tx,intent.ty);\n  }\n\n  private buildRoute(sx:number,sy:number,tx:number,ty:number){\n    const source=this.buildingAt(sx,sy);\n    const target=this.buildingAt(tx,ty);\n    if(source&&target&&source===target)return[{x:tx,y:ty}];\n    const route:Point[]=[];\n    if(source){const door=this.doorPoints(source);route.push(door.inside,door.outside);}\n    if(target){const door=this.doorPoints(target);route.push(door.outside,door.inside);}\n    route.push({x:tx,y:ty});\n    return route;\n  }\n\n  private buildingAt(x:number,y:number){return BUILDINGS.find((b)=>x>b.x+18&&x<b.x+b.w-18&&y>b.y+18&&y<b.y+b.h-18);}\n\n  private doorPoints(b:Building){\n    const margin=PLAYER_RADIUS+14;\n    const wall=18;\n    if(b.doorSide==='north'){\n      const x=b.x+b.w*b.doorOffset;\n      return{outside:{x,y:b.y-margin},inside:{x,y:b.y+wall+margin}};\n    }\n    if(b.doorSide==='south'){\n      const x=b.x+b.w*b.doorOffset;\n      return{outside:{x,y:b.y+b.h+margin},inside:{x,y:b.y+b.h-wall-margin}};\n    }\n    if(b.doorSide==='west'){\n      const y=b.y+b.h*b.doorOffset;\n      return{outside:{x:b.x-margin,y},inside:{x:b.x+wall+margin,y}};\n    }\n    const y=b.y+b.h*b.doorOffset;\n    return{outside:{x:b.x+b.w+margin,y},inside:{x:b.x+b.w-wall-margin,y}};\n  }\n\n  private advanceAiRoute(p:PlayerState,intent:AiIntent){\n    while(intent.route.length&&distance(p.x,p.y,intent.route[0]!.x,intent.route[0]!.y)<44)intent.route.shift();\n  }\n\n  private damage(p:PlayerState,amount:number,attackerId:string,reason:string){\n    if(!p.alive)return;\n    this.cancelHeal(p);\n    let actual=amount;\n    if(p.armor>0&&reason==='총기'){\n      const absorbed=actual*.3;\n      actual-=absorbed;\n      p.armor=Math.max(0,p.armor-absorbed*1.5);\n    }\n    const attacker=this.state.players.get(attackerId);\n    const hitAngle=attacker?Math.atan2(p.y-attacker.y,p.x-attacker.x):p.lastHitAngle;\n    p.hitSeq++;\n    p.lastHitAngle=hitAngle;\n    p.lastHitDamage=actual;\n    if(attacker&&reason!=='자기장'){\n      const power=this.knockbackPower(attacker,reason);\n      if(power>0){\n        const current=this.knockback.get(p.id)??{vx:0,vy:0};\n        current.vx+=Math.cos(hitAngle)*power;\n        current.vy+=Math.sin(hitAngle)*power;\n        const max=420;\n        const len=Math.hypot(current.vx,current.vy);\n        if(len>max){current.vx=current.vx/len*max;current.vy=current.vy/len*max;}\n        this.knockback.set(p.id,current);\n      }\n    }\n    p.hp-=actual;\n    if(attacker)attacker.damageDone+=actual;\n    if(p.hp<=0){\n      p.hp=0;\n      p.alive=false;\n      p.phase='dead';\n      p.aiState='DEAD';\n      this.knockback.delete(p.id);\n      this.aiIntent.delete(p.id);\n      this.reloadUntil.delete(p.id);\n      this.state.placements.unshift(p.name);\n      if(attacker&&attacker.id!==p.id){\n        attacker.kills++;\n        this.broadcast('killfeed',{killer:attacker.name,victim:p.name,reason});\n      }else this.broadcast('killfeed',{killer:reason,victim:p.name,reason});\n      this.dropInventory(p);\n    }\n  }\n\n  private knockbackPower(attacker:PlayerState,reason:string):number{\n    if(reason==='주먹')return 230;\n    if(reason==='야구방망이')return 320;\n    if(reason==='프라이팬')return 360;\n    if(reason==='쇠파이프')return 285;\n    if(reason==='식칼')return 165;\n    if(reason==='총기')return attacker.equipped==='shotgun'?230:attacker.equipped==='rifle'?90:attacker.equipped==='pistol'?72:38;\n    return 0;\n  }\n\n  private dropInventory(p:PlayerState){\n    const kinds=[p.primary,p.secondary,p.melee!=='fists'?p.melee:'',p.armor>0?'vest':'',p.bandages?'bandage':'',p.medkits?'medkit':''].filter(Boolean);\n    for(const k of kinds){\n      const l=new LootState();\n      l.id=`loot-${++this.lootSeq}`;\n      l.kind=k;\n      l.x=clamp(p.x+(Math.random()-.5)*55,20,WORLD_SIZE-20);\n      l.y=clamp(p.y+(Math.random()-.5)*55,20,WORLD_SIZE-20);\n      this.state.loot.set(l.id,l);\n    }\n  }\n\n  private finishCheck(){\n    const alive=[...this.state.players.values()].filter((p)=>p.alive);\n    this.state.aliveCount=alive.length;\n    if(alive.length<=1&&this.state.players.size>1&&this.state.phase!=='FINISHED'){\n      this.state.phase='FINISHED';\n      this.state.winner=alive[0]?.name??'없음';\n      if(alive[0])this.state.placements.unshift(alive[0].name);\n      this.broadcast('result',{winner:this.state.winner,placements:[...this.state.placements]});\n    }\n  }\n\n  private resetLobby(){\n    this.clearTransient();\n    for(const [id,p] of [...this.state.players]){\n      if(p.ai)this.state.players.delete(id);\n      else{\n        p.ready=false;\n        p.alive=true;\n        p.hp=100;\n        p.phase='lobby';\n        p.primary='';\n        p.secondary='';\n        p.melee='fists';\n        p.equipped='fists';\n        p.magazine=0;\n        p.pistolMagazine=0;\n        p.smgMagazine=0;\n        p.rifleMagazine=0;\n        p.shotgunMagazine=0;\n        p.bandages=0;\n        p.medkits=0;\n        p.healingKind='';\n        p.healingProgress=0;\n        p.attackSeq=0;\n        p.hitSeq=0;\n        p.lastHitAngle=0;\n        p.lastHitDamage=0;\n        p.aiState='';\n      }\n    }\n    this.state.phase='LOBBY';\n    this.state.winner='';\n    this.state.placements.clear();\n    this.state.aliveCount=this.state.players.size;\n  }\n\n  private getWeaponMagazine(p:PlayerState,id:WeaponId):number{\n    if(id==='pistol')return p.pistolMagazine;\n    if(id==='smg')return p.smgMagazine;\n    if(id==='rifle')return p.rifleMagazine;\n    if(id==='shotgun')return p.shotgunMagazine;\n    return 0;\n  }\n\n  private setWeaponMagazine(p:PlayerState,id:WeaponId,value:number,sync=true){\n    const amount=Math.max(0,Math.floor(value));\n    if(id==='pistol')p.pistolMagazine=amount;\n    else if(id==='smg')p.smgMagazine=amount;\n    else if(id==='rifle')p.rifleMagazine=amount;\n    else if(id==='shotgun')p.shotgunMagazine=amount;\n    if(sync&&p.equipped===id)p.magazine=amount;\n  }\n\n  private syncMagazine(p:PlayerState){\n    const id=p.equipped as WeaponId;\n    p.magazine=id in WEAPONS&&id!=='fists'?this.getWeaponMagazine(p,id):0;\n  }\n\n  private getAmmo(p:PlayerState,t:string){return t==='small'?p.smallAmmo:t==='rifle'?p.rifleAmmo:t==='shells'?p.shells:0;}\n  private setAmmo(p:PlayerState,t:string,v:number){if(t==='small')p.smallAmmo=v;else if(t==='rifle')p.rifleAmmo=v;else if(t==='shells')p.shells=v;}\n  private now(){return this.clock.elapsedTime/1000;}\n  private angleDiff(a:number,b:number){return Math.atan2(Math.sin(a-b),Math.cos(a-b));}\n\n  private segmentRect(x1:number,y1:number,x2:number,y2:number,r:{x:number;y:number;w:number;h:number}){\n    const steps=Math.max(1,Math.ceil(distance(x1,y1,x2,y2)/18));\n    for(let i=0;i<=steps;i++){\n      const t=i/steps;\n      const x=x1+(x2-x1)*t;\n      const y=y1+(y2-y1)*t;\n      if(x>=r.x&&x<=r.x+r.w&&y>=r.y&&y<=r.y+r.h)return true;\n    }\n    return false;\n  }\n}\n", "client/src/GameScene.ts": "import Phaser from 'phaser';\nimport {\n  BUILDINGS, LOOT_COLORS, LOOT_LABELS, MELEE_WEAPONS, OBSTACLES, PLAYER_RADIUS, PLAYER_SPEED, REGIONS, WEAPONS, WORLD_SIZE, circleHitsRect, clamp,\n  type EquippedId, type LootKind, type WeaponId, type MeleeId\n} from '@drop8/shared';\nimport type { Network } from './network';\n\ntype DisplayPoint={x:number;y:number};\n\nexport class GameScene extends Phaser.Scene {\n  private staticG!:Phaser.GameObjects.Graphics;\n  private dynamicG!:Phaser.GameObjects.Graphics;\n  private slowG!:Phaser.GameObjects.Graphics;\n  private hitG!:Phaser.GameObjects.Graphics;\n  private mini!:Phaser.GameObjects.Graphics;\n  private pickupText!:Phaser.GameObjects.Text;\n  private fpsText!:Phaser.GameObjects.Text;\n  private keys!:Record<string,Phaser.Input.Keyboard.Key>;\n  private seq=0;\n  private lastInput=0;\n  private lastFire=0;\n  private lastMiniDraw=0;\n  private lastSlowDraw=0;\n  private lastFpsDraw=0;\n  private mapOpen=false;\n  private spectateIndex=0;\n  private displayPlayers=new Map<string,DisplayPoint>();\n  private displayBullets=new Map<string,DisplayPoint>();\n  private lastAttackSeq=new Map<string,number>();\n  private attackStartedAt=new Map<string,number>();\n  private lastHitSeq=new Map<string,number>();\n  private hitStartedAt=new Map<string,number>();\n  private predictedLocal:DisplayPoint|null=null;\n  private localAimAngle=0;\n  private localHitUntil=0;\n  private localHitAngle=0;\n\n  constructor(private net:Network){super('game');}\n\n  create(){\n    this.cameras.main.setBounds(0,0,WORLD_SIZE,WORLD_SIZE);\n    this.cameras.main.setBackgroundColor('#153424');\n    this.staticG=this.add.graphics().setDepth(0);\n    this.slowG=this.add.graphics().setDepth(3);\n    this.dynamicG=this.add.graphics().setDepth(5);\n    this.hitG=this.add.graphics().setScrollFactor(0).setDepth(45);\n    this.mini=this.add.graphics().setScrollFactor(0).setDepth(40);\n    this.pickupText=this.add.text(this.scale.width/2,this.scale.height-92,'',{fontFamily:'sans-serif',fontSize:'18px',fontStyle:'bold',color:'#ffffff',backgroundColor:'#071018dd',padding:{x:12,y:8}}).setOrigin(.5).setScrollFactor(0).setDepth(50).setVisible(false);\n    this.fpsText=this.add.text(12,12,'',{fontFamily:'monospace',fontSize:'12px',color:'#9fb2bf',backgroundColor:'#071018aa',padding:{x:6,y:4}}).setScrollFactor(0).setDepth(50);\n    this.keys=this.input.keyboard!.addKeys('W,A,S,D,E,R,ONE,TWO,THREE,FOUR,M,SPACE,ENTER,LEFT,RIGHT') as Record<string,Phaser.Input.Keyboard.Key>;\n    this.keys.LEFT.on('down',()=>{this.spectateIndex=Math.max(0,this.spectateIndex-1);});\n    this.keys.RIGHT.on('down',()=>{this.spectateIndex++;});\n    this.keys.E.on('down',()=>this.net.send('pickup'));\n    this.keys.R.on('down',()=>this.net.send('reload'));\n    this.keys.ONE.on('down',()=>this.net.send('switch',{slot:1}));\n    this.keys.TWO.on('down',()=>this.net.send('switch',{slot:2}));\n    this.keys.THREE.on('down',()=>this.net.send('switch',{slot:3}));\n    this.keys.FOUR.on('down',()=>this.net.send('heal',{kind:'auto'}));\n    this.keys.SPACE.on('down',()=>this.net.send('jump'));\n    this.keys.M.on('down',()=>{this.mapOpen=!this.mapOpen;this.lastMiniDraw=0;});\n    this.scale.on('resize',(size:Phaser.Structs.Size)=>{\n      this.pickupText.setPosition(size.width/2,size.height-92);\n      this.lastMiniDraw=0;\n    });\n    this.drawStaticMap();\n  }\n\n  update(time:number){\n    const s=this.net.snapshot;\n    if(!s)return;\n    const me=this.local();\n    if(me){\n      const rawX=(this.keys.D.isDown?1:0)-(this.keys.A.isDown?1:0);\n      const rawY=(this.keys.S.isDown?1:0)-(this.keys.W.isDown?1:0);\n      const inputLength=Math.hypot(rawX,rawY)||1;\n      const x=rawX/inputLength,y=rawY/inputLength;\n      const pointer=this.input.activePointer;\n      const aimBase=this.predictedLocal??{x:me.x,y:me.y};\n      this.localAimAngle=Math.atan2(pointer.worldY-aimBase.y,pointer.worldX-aimBase.x);\n      if(me.alive&&me.phase==='landed')this.updateLocalPrediction(me,x,y,this.game.loop.delta/1000);\n      else this.predictedLocal={x:me.x,y:me.y};\n      const alive=s.players.filter(p=>p.alive);\n      const target=me.alive?me:(alive.length?alive[this.spectateIndex%alive.length]:me);\n      const shown=target.id===me.id&&this.predictedLocal?this.predictedLocal:this.getDisplayPlayer(target.id,target.x,target.y,.2);\n      this.cameras.main.centerOn(shown.x,shown.y);\n      if(time-this.lastInput>=50){\n        this.net.send('input',{x,y,angle:this.localAimAngle,seq:++this.seq});\n        this.lastInput=time;\n      }\n      if(pointer.isDown&&time-this.lastFire>=55){\n        this.net.send(me.equipped==='fists'||me.equipped in MELEE_WEAPONS?'melee':'fire');\n        this.lastFire=time;\n      }\n    }\n    this.updateHitState(s,time);\n    if(time-this.lastSlowDraw>=100){this.drawSlowLayers(s);this.lastSlowDraw=time;}\n    this.drawDynamic(time);\n    this.drawHitEffects(time);\n    this.updatePickupPrompt();\n    if(time-this.lastFpsDraw>=500){this.fpsText.setText(`FPS ${Math.round(this.game.loop.actualFps)}`);this.lastFpsDraw=time;}\n  }\n\n  private local(){return this.net.snapshot?.players.find(p=>p.id===this.net.sessionId);}\n\n  private drawStaticMap(){\n    const g=this.staticG;\n    g.clear();\n    g.fillStyle(0x153424).fillRect(0,0,WORLD_SIZE,WORLD_SIZE);\n    for(const r of REGIONS){\n      g.fillStyle(r.color,.22).fillRoundedRect(r.x,r.y,r.w,r.h,28);\n      g.lineStyle(3,0xffffff,.1).strokeRoundedRect(r.x,r.y,r.w,r.h,28);\n      this.add.text(r.x+20,r.y+18,r.name,{fontFamily:'sans-serif',fontSize:'30px',fontStyle:'bold',color:'#ffffff55'}).setDepth(.5);\n    }\n    for(const b of BUILDINGS){\n      g.fillStyle(0x26373d,.92).fillRect(b.x+18,b.y+18,Math.max(1,b.w-36),Math.max(1,b.h-36));\n      g.lineStyle(2,0x87a1ac,.2).strokeRect(b.x+18,b.y+18,Math.max(1,b.w-36),Math.max(1,b.h-36));\n    }\n    for(const wall of OBSTACLES){\n      g.fillStyle(0x4a5b63).fillRect(wall.x,wall.y,wall.w,wall.h);\n      g.lineStyle(2,0x10181d,.9).strokeRect(wall.x,wall.y,wall.w,wall.h);\n    }\n  }\n\n  private drawDynamic(time:number){\n    const s=this.net.snapshot;\n    if(!s)return;\n    const g=this.dynamicG;\n    g.clear();\n    const view=this.cameras.main.worldView;\n    const visible=(x:number,y:number,m=120)=>x>=view.x-m&&x<=view.right+m&&y>=view.y-m&&y<=view.bottom+m;\n\n    const activeBulletIds=new Set<string>();\n    for(const b of s.bullets){\n      activeBulletIds.add(b.id);\n      if(!visible(b.x,b.y,40))continue;\n      const d=this.getDisplayBullet(b.id,b.x,b.y);\n      g.lineStyle(3,0xffef9a,.9).lineBetween(d.x-b.vx*.012,d.y-b.vy*.012,d.x,d.y);\n      g.fillStyle(0xfff6bd).fillCircle(d.x,d.y,3);\n    }\n    for(const id of this.displayBullets.keys())if(!activeBulletIds.has(id))this.displayBullets.delete(id);\n\n    if(['PLANE','DROP'].includes(s.phase)){\n      g.lineStyle(4,0xffffff,.2).lineBetween(0,s.planeY,s.planeEndX,s.planeEndY);\n      g.fillStyle(0xf1f3f4).fillTriangle(s.planeX+30,s.planeY,s.planeX-25,s.planeY-18,s.planeX-25,s.planeY+18);\n    }\n\n    const activeIds=new Set<string>();\n    for(const p of s.players){\n      if(!p.alive||!visible(p.x,p.y,100))continue;\n      activeIds.add(p.id);\n      const local=p.id===this.net.sessionId;\n      const pos=local&&this.predictedLocal?this.predictedLocal:this.getDisplayPlayer(p.id,p.x,p.y,.24);\n      const shown=local?{...p,angle:this.localAimAngle}:p;\n      this.drawPlayer(g,shown,pos.x,pos.y,time);\n    }\n    for(const id of this.displayPlayers.keys())if(!activeIds.has(id)&&!s.players.some(p=>p.id===id))this.displayPlayers.delete(id);\n\n    if(time-this.lastMiniDraw>=100){\n      this.drawMini(s);\n      this.lastMiniDraw=time;\n    }\n  }\n\n  private drawSlowLayers(s:any){\n    const g=this.slowG;\n    g.clear();\n    const view=this.cameras.main.worldView;\n    const visible=(x:number,y:number,m=120)=>x>=view.x-m&&x<=view.right+m&&y>=view.y-m&&y<=view.bottom+m;\n    g.lineStyle(6,0x4db5ff,.72).strokeCircle(s.zoneX,s.zoneY,s.zoneRadius);\n    g.lineStyle(3,0xffffff,.2).strokeCircle(s.zoneX,s.zoneY,s.nextZoneRadius);\n    for(const l of s.loot){if(visible(l.x,l.y,80))this.drawLootIcon(g,l.kind as LootKind,l.x,l.y,1);}\n  }\n\n  private updateLocalPrediction(me:any,x:number,y:number,dt:number){\n    if(!this.predictedLocal)this.predictedLocal={x:me.x,y:me.y};\n    const error=Math.hypot(this.predictedLocal.x-me.x,this.predictedLocal.y-me.y);\n    if(error>130){this.predictedLocal.x=me.x;this.predictedLocal.y=me.y;}\n    else if(error>16){this.predictedLocal.x=Phaser.Math.Linear(this.predictedLocal.x,me.x,.085);this.predictedLocal.y=Phaser.Math.Linear(this.predictedLocal.y,me.y,.085);}\n    const ranged=WEAPONS[(me.equipped||'fists') as WeaponId];\n    const melee=MELEE_WEAPONS[me.equipped as MeleeId];\n    const multiplier=ranged?.moveMultiplier??melee?.moveMultiplier??1;\n    const step=Math.min(.04,Math.max(0,dt))*PLAYER_SPEED*multiplier;\n    this.movePredicted(x*step,y*step);\n  }\n\n  private movePredicted(dx:number,dy:number){\n    if(!this.predictedLocal)return;\n    const nx=clamp(this.predictedLocal.x+dx,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS);\n    const ny=clamp(this.predictedLocal.y+dy,PLAYER_RADIUS,WORLD_SIZE-PLAYER_RADIUS);\n    if(!OBSTACLES.some(r=>circleHitsRect(nx,this.predictedLocal!.y,PLAYER_RADIUS,r)))this.predictedLocal.x=nx;\n    if(!OBSTACLES.some(r=>circleHitsRect(this.predictedLocal!.x,ny,PLAYER_RADIUS,r)))this.predictedLocal.y=ny;\n  }\n\n  private updateHitState(s:any,time:number){\n    const active=new Set<string>();\n    for(const p of s.players){\n      active.add(p.id);\n      const seq=Number(p.hitSeq??0),prev=this.lastHitSeq.get(p.id);\n      if(prev===undefined)this.lastHitSeq.set(p.id,seq);\n      else if(prev!==seq){\n        this.lastHitSeq.set(p.id,seq);this.hitStartedAt.set(p.id,time);\n        if(p.id===this.net.sessionId){this.localHitUntil=time+220;this.localHitAngle=Number(p.lastHitAngle??0);this.cameras.main.shake(95,Math.min(.012,.003+Number(p.lastHitDamage??0)/6000));}\n      }\n    }\n    for(const id of this.lastHitSeq.keys())if(!active.has(id)){this.lastHitSeq.delete(id);this.hitStartedAt.delete(id);}\n  }\n\n  private drawHitEffects(time:number){\n    const g=this.hitG;g.clear();\n    if(time>=this.localHitUntil)return;\n    const pulse=(this.localHitUntil-time)/220,w=this.scale.width,h=this.scale.height;\n    g.fillStyle(0xff2538,.06+.11*pulse).fillRect(0,0,w,h);\n    g.lineStyle(8,0xff3348,.2+.45*pulse).strokeRect(4,4,w-8,h-8);\n    const cx=w/2,cy=h/2,r=72;\n    const ax=cx+Math.cos(this.localHitAngle)*r,ay=cy+Math.sin(this.localHitAngle)*r;\n    g.lineStyle(6,0xff5968,.85*pulse).lineBetween(cx,cy,ax,ay);\n    g.fillStyle(0xff5968,.9*pulse).fillCircle(ax,ay,7);\n  }\n\n  private drawPlayer(g:Phaser.GameObjects.Graphics,p:any,x:number,y:number,time:number){\n    const color=p.id===this.net.sessionId?0x45d7ff:p.ai?0xff8b5f:0xf06dba;\n    const hitAt=this.hitStartedAt.get(p.id)??-999;\n    const hitPulse=Math.max(0,1-(time-hitAt)/180);\n    const bodyColor=hitPulse>0&&Math.floor((time-hitAt)/45)%2===0?0xffffff:color;\n    const scale=p.phase==='falling'?1.7:p.phase==='parachute'?1.35:1;\n    const altitudeOffset=20+Math.min(50,p.altitude/15);\n    g.fillStyle(0x000000,.22).fillEllipse(x,y+altitudeOffset,40,18);\n    g.fillStyle(bodyColor).fillCircle(x,y,20*scale);\n    if(hitPulse>0)g.lineStyle(4,0xff4c57,hitPulse).strokeCircle(x,y,27+8*(1-hitPulse));\n    g.lineStyle(4,0xffffff,p.id===this.net.sessionId?1:.38).strokeCircle(x,y,20*scale);\n\n    const attackSeq=Number(p.attackSeq??0);\n    const previous=this.lastAttackSeq.get(p.id);\n    if(previous===undefined)this.lastAttackSeq.set(p.id,attackSeq);\n    else if(previous!==attackSeq){this.lastAttackSeq.set(p.id,attackSeq);this.attackStartedAt.set(p.id,time);}\n    const started=this.attackStartedAt.get(p.id)??-999;\n    const attackProgress=Math.max(0,Math.min(1,(time-started)/170));\n    const attackPulse=attackProgress<1?Math.sin(attackProgress*Math.PI):0;\n    this.drawHeldItem(g,p.equipped as EquippedId,x,y,p.angle,attackPulse,attackSeq);\n\n    g.fillStyle(p.hp>40?0x55dd8c:0xff5f67).fillRect(x-25,y-37,50*Math.max(0,p.hp)/100,5);\n  }\n\n  private drawHeldItem(g:Phaser.GameObjects.Graphics,id:EquippedId,x:number,y:number,a:number,pulse:number,seq:number){\n    const pt=(forward:number,side:number)=>({x:x+Math.cos(a)*forward-Math.sin(a)*side,y:y+Math.sin(a)*forward+Math.cos(a)*side});\n    if(id==='fists'){\n      const side=seq%2===0?1:-1;\n      for(const hand of [-1,1]){\n        const extend=hand===side?22*pulse:0;\n        const elbow=pt(14+extend*.35,hand*12);\n        const fist=pt(24+extend,hand*12);\n        g.lineStyle(6,0xf0b28d,1).lineBetween(elbow.x,elbow.y,fist.x,fist.y);\n        g.fillStyle(0xffc39d).fillCircle(fist.x,fist.y,6);\n      }\n      return;\n    }\n\n    if(id in MELEE_WEAPONS){\n      const swing=a-.7+1.4*pulse;\n      const hand=pt(15,0);\n      const length=id==='knife'?34:id==='pan'?45:54;\n      const end={x:hand.x+Math.cos(swing)*length,y:hand.y+Math.sin(swing)*length};\n      g.lineStyle(id==='bat'?9:id==='pipe'?7:5,id==='bat'?0xc98b55:id==='pipe'?0x9eb1bb:0xd9e4ea,1).lineBetween(hand.x,hand.y,end.x,end.y);\n      if(id==='pan')g.fillStyle(0x9aaab4).fillCircle(end.x,end.y,13);\n      if(id==='knife')g.fillStyle(0xe9f1f5).fillTriangle(end.x,end.y,end.x-Math.cos(swing-.55)*15,end.y-Math.sin(swing-.55)*15,end.x-Math.cos(swing+.55)*15,end.y-Math.sin(swing+.55)*15);\n      return;\n    }\n\n    const recoil=4*pulse;\n    const hand=pt(15-recoil,0);\n    if(id==='pistol'){\n      const muzzle=pt(40-recoil,0),grip=pt(23-recoil,9);\n      g.lineStyle(7,0x222a31,1).lineBetween(hand.x,hand.y,muzzle.x,muzzle.y);\n      g.lineStyle(6,0x39454d,1).lineBetween(pt(23-recoil,1).x,pt(23-recoil,1).y,grip.x,grip.y);\n      g.fillStyle(0xffd451).fillCircle(muzzle.x,muzzle.y,3);\n    }else if(id==='smg'){\n      const end=pt(46-recoil,0),stock=pt(7-recoil,0),mag=pt(29-recoil,11);\n      g.lineStyle(10,0x303a42,1).lineBetween(stock.x,stock.y,end.x,end.y);\n      g.lineStyle(7,0x1e252b,1).lineBetween(pt(28-recoil,2).x,pt(28-recoil,2).y,mag.x,mag.y);\n      g.fillStyle(0xffb84d).fillCircle(end.x,end.y,3);\n    }else if(id==='rifle'){\n      const end=pt(58-recoil,0),stockTop=pt(4-recoil,-7),stockBottom=pt(4-recoil,7),stockBack=pt(-5-recoil,0),mag=pt(32-recoil,12);\n      g.lineStyle(7,0x303940,1).lineBetween(hand.x,hand.y,end.x,end.y);\n      g.lineStyle(5,0x4a3427,1).lineBetween(stockTop.x,stockTop.y,stockBack.x,stockBack.y).lineBetween(stockBack.x,stockBack.y,stockBottom.x,stockBottom.y);\n      g.lineStyle(6,0x1c2429,1).lineBetween(pt(31-recoil,2).x,pt(31-recoil,2).y,mag.x,mag.y);\n      g.fillStyle(0xff8f4d).fillCircle(end.x,end.y,3);\n    }else if(id==='shotgun'){\n      const endA=pt(58-recoil,-3),endB=pt(58-recoil,3),pump=pt(36-recoil,0);\n      g.lineStyle(5,0x30383e,1).lineBetween(hand.x,hand.y,endA.x,endA.y).lineBetween(hand.x,hand.y,endB.x,endB.y);\n      g.fillStyle(0x8b5b38).fillCircle(pump.x,pump.y,6);\n      g.fillStyle(0xff6b55).fillCircle(endA.x,endA.y,3).fillCircle(endB.x,endB.y,3);\n    }\n  }\n\n  private drawLootIcon(g:Phaser.GameObjects.Graphics,kind:LootKind,x:number,y:number,scale:number){\n    const c=LOOT_COLORS[kind]??0xffffff;\n    g.fillStyle(0x061018,.72).fillCircle(x,y,16*scale);\n    g.lineStyle(2,c,1);\n    const line=(x1:number,y1:number,x2:number,y2:number,w=3)=>{g.lineStyle(w,c,1).lineBetween(x+x1*scale,y+y1*scale,x+x2*scale,y+y2*scale);};\n    if(kind==='pistol'){line(-8,-2,8,-2,4);line(1,0,1,8,4);g.fillStyle(c).fillCircle(x+9*scale,y-2*scale,2.5*scale);}\n    else if(kind==='smg'){line(-10,0,10,0,6);line(1,2,1,10,4);line(-10,0,-14,5,3);g.fillStyle(c).fillCircle(x+11*scale,y,2.5*scale);}\n    else if(kind==='rifle'){line(-13,0,13,0,4);line(-13,0,-18,-6,3);line(2,1,2,10,4);g.fillStyle(c).fillCircle(x+14*scale,y,2.5*scale);}\n    else if(kind==='shotgun'){line(-14,-3,14,-3,3);line(-14,3,14,3,3);g.fillStyle(c).fillCircle(x+15*scale,y-3*scale,2).fillCircle(x+15*scale,y+3*scale,2);}\n    else if(kind==='small_ammo'||kind==='rifle_ammo'||kind==='shells'){for(const dx of [-6,0,6]){line(dx,-7,dx,6,3);g.fillStyle(c).fillCircle(x+dx*scale,y-7*scale,2*scale);}}\n    else if(kind==='vest'){g.fillStyle(c).fillTriangle(x-10*scale,y-9*scale,x+10*scale,y-9*scale,x,y+12*scale);g.fillStyle(0x061018).fillCircle(x,y-2*scale,4*scale);}\n    else if(kind==='bandage'){g.fillStyle(c).fillRoundedRect(x-11*scale,y-5*scale,22*scale,10*scale,4*scale);g.fillStyle(0xffffff).fillCircle(x,y,3*scale);}\n    else if(kind==='medkit'){g.fillStyle(c).fillRoundedRect(x-11*scale,y-11*scale,22*scale,22*scale,4*scale);g.lineStyle(4,0xffffff,1).lineBetween(x-6*scale,y,x+6*scale,y).lineBetween(x,y-6*scale,x,y+6*scale);}\n    else if(kind==='bat'){line(-11,8,11,-9,7);}\n    else if(kind==='pipe'){line(-11,8,11,-9,5);g.fillStyle(c).fillCircle(x+11*scale,y-9*scale,3*scale);}\n    else if(kind==='knife'){line(-10,8,2,-3,4);g.fillStyle(c).fillTriangle(x+2*scale,y-3*scale,x+13*scale,y-10*scale,x+7*scale,y+2*scale);}\n    else if(kind==='pan'){line(-11,10,3,-4,4);g.fillStyle(c).fillCircle(x+8*scale,y-9*scale,8*scale);}\n  }\n\n  private updatePickupPrompt(){\n    const s=this.net.snapshot,me=this.local();\n    if(!s||!me||!me.alive||me.phase!=='landed'){this.pickupText.setVisible(false);return;}\n    let nearest:any;let best=105*105;\n    for(const l of s.loot){const dx=l.x-me.x,dy=l.y-me.y,d=dx*dx+dy*dy;if(d<best){best=d;nearest=l;}}\n    if(!nearest){this.pickupText.setVisible(false);return;}\n    const label=LOOT_LABELS[nearest.kind as LootKind]??nearest.kind;\n    this.pickupText.setText(`E  줍기 · ${label}`).setVisible(true);\n  }\n\n  private getDisplayPlayer(id:string,x:number,y:number,alpha:number){\n    const current=this.displayPlayers.get(id)??{x,y};\n    current.x=Phaser.Math.Linear(current.x,x,alpha);\n    current.y=Phaser.Math.Linear(current.y,y,alpha);\n    this.displayPlayers.set(id,current);\n    return current;\n  }\n\n  private getDisplayBullet(id:string,x:number,y:number){\n    const current=this.displayBullets.get(id)??{x,y};\n    current.x=Phaser.Math.Linear(current.x,x,.55);\n    current.y=Phaser.Math.Linear(current.y,y,.55);\n    this.displayBullets.set(id,current);\n    return current;\n  }\n\n  private drawMini(s:any){\n    const g=this.mini;\n    g.clear();\n    const w=this.mapOpen?420:190,h=this.mapOpen?420:190,x=this.scale.width-w-14,y=14,sc=w/WORLD_SIZE;\n    g.fillStyle(0x061018,.9).fillRoundedRect(x,y,w,h,12);\n    for(const r of REGIONS)g.fillStyle(r.color,.45).fillRect(x+r.x*sc,y+r.y*sc,r.w*sc,r.h*sc);\n    for(const b of BUILDINGS)g.fillStyle(0x70818a,.52).fillRect(x+b.x*sc,y+b.y*sc,Math.max(1,b.w*sc),Math.max(1,b.h*sc));\n    g.lineStyle(2,0x4db5ff).strokeCircle(x+s.zoneX*sc,y+s.zoneY*sc,s.zoneRadius*sc);\n    for(const p of s.players){if(!p.alive)continue;g.fillStyle(p.id===this.net.sessionId?0x54dcff:0xff686e).fillCircle(x+p.x*sc,y+p.y*sc,p.id===this.net.sessionId?5:3);}\n  }\n}\n", "client/src/main.ts": "import Phaser from 'phaser';\nimport { GAME_NAME, MAX_PLAYERS, MELEE_WEAPONS, WEAPONS } from '@drop8/shared';\nimport { GameScene } from './GameScene';\nimport { Network } from './network';\nimport './style.css';\n\nconst $=<T extends HTMLElement>(id:string)=>document.getElementById(id) as T;\nconst net=new Network();\nlet game:Phaser.Game|null=null;\nlet chatting=false;\nlet lastHudAt=0;\nconst home=$('home');\nconst lobby=$('lobby');\nconst gameEl=$('game');\nconst error=$('homeError');\nconst nickname=$<HTMLInputElement>('nickname');\nconst roomCode=$<HTMLInputElement>('roomCode');\nconst password=$<HTMLInputElement>('password');\n\nnickname.value=localStorage.getItem('drop8-nick')??'';\nroomCode.value=new URLSearchParams(location.search).get('room')??'';\n\nfunction nick(){\n  const n=nickname.value.trim()||`유저${Math.floor(Math.random()*99)+1}`;\n  localStorage.setItem('drop8-nick',n);\n  return n;\n}\n\nasync function connect(create:boolean){\n  error.textContent='연결 중...';\n  try{\n    const opts={nickname:nick(),password:password.value,roomPassword:password.value,fillAi:true,difficulty:'normal',zoneSpeed:'normal'};\n    if(create)await net.create(opts);\n    else await net.join(roomCode.value.trim(),opts);\n    home.classList.add('hidden');\n    lobby.classList.remove('hidden');\n    history.replaceState(null,'',`?room=${net.room?.roomId}`);\n    error.textContent='';\n    render();\n  }catch(e){\n    error.textContent=e instanceof Error?e.message:'방 연결 실패';\n  }\n}\n\n$('createBtn').onclick=()=>void connect(true);\n$('joinBtn').onclick=()=>void connect(false);\n$('readyBtn').onclick=()=>net.send('ready');\n$('startBtn').onclick=()=>net.send('start');\n$('copyBtn').onclick=()=>void navigator.clipboard.writeText(location.href);\n$('gameCodeText').onclick=()=>{\n  const code=net.snapshot?.roomCode;\n  if(code)void navigator.clipboard.writeText(`${location.origin}?room=${code}`);\n};\n$('rematchBtn').onclick=()=>net.send('rematch');\n$('fillAi').onchange=sendSettings;\n$('difficulty').onchange=sendSettings;\n$('zoneSpeed').onchange=sendSettings;\n\nfunction sendSettings(){\n  net.send('settings',{\n    fillAi:$<HTMLInputElement>('fillAi').checked,\n    difficulty:$<HTMLSelectElement>('difficulty').value,\n    zoneSpeed:$<HTMLSelectElement>('zoneSpeed').value,\n  });\n}\n\n$('lobbyChat').onsubmit=(e)=>{\n  e.preventDefault();\n  const input=$<HTMLInputElement>('lobbyChatInput');\n  net.send('chat',{text:input.value});\n  input.value='';\n};\n\n$('gameChat').onsubmit=(e)=>{\n  e.preventDefault();\n  const input=$<HTMLInputElement>('gameChatInput');\n  net.send('chat',{text:input.value});\n  input.value='';\n  toggleChat(false);\n};\n\nwindow.addEventListener('keydown',(e)=>{\n  if(e.key==='Enter'&&!lobby.classList.contains('hidden'))return;\n  if(e.key==='Enter'&&!gameEl.classList.contains('hidden')){\n    e.preventDefault();\n    toggleChat(!chatting);\n  }\n  if((e.key==='t'||e.key==='T')&&!gameEl.classList.contains('hidden')&&!chatting){\n    e.preventDefault();\n    $('quickChat').classList.toggle('hidden');\n  }\n});\n\nfor(const button of Array.from(document.querySelectorAll<HTMLButtonElement>('#quickChat button'))){\n  button.onclick=()=>{\n    net.send('chat',{text:button.dataset.msg??''});\n    $('quickChat').classList.add('hidden');\n  };\n}\n\nfunction toggleChat(on:boolean){\n  chatting=on;\n  $('gameChat').classList.toggle('hidden',!on);\n  if(on)$<HTMLInputElement>('gameChatInput').focus();\n}\n\nnet.listeners.add(render);\nnet.messages.add((type,p)=>{\n  if(type==='chat')addMessage(p);\n  if(type==='killfeed')addKill(p);\n  if(type==='result'){\n    $('result').classList.remove('hidden');\n    $('resultTitle').textContent=p.winner?`${p.winner} 우승!`:'경기 종료';\n    $('resultStats').textContent=(p.placements??[]).map((n:string,i:number)=>`${i+1}위 ${n}`).join(' · ');\n  }\n  if(type==='error')alert(p);\n});\n\nfunction addMessage(p:any){\n  const box=net.snapshot?.phase==='LOBBY'?$('lobbyMessages'):$('gameMessages');\n  const d=document.createElement('div');\n  d.className=`message ${p.channel==='system'?'system':''}`;\n  d.textContent=`[${p.sender}] ${p.text}`;\n  box.append(d);\n  while(box.children.length>30)box.firstChild?.remove();\n  box.scrollTop=box.scrollHeight;\n  setTimeout(()=>{if(box.id==='gameMessages')d.remove();},6500);\n}\n\nfunction addKill(p:any){\n  const d=document.createElement('div');\n  d.className='kill';\n  d.textContent=`${p.killer} → ${p.victim}`;\n  $('killfeed').append(d);\n  setTimeout(()=>d.remove(),6000);\n}\n\nfunction createGame(){\n  game=new Phaser.Game({\n    type:Phaser.WEBGL,\n    parent:'gameCanvas',\n    width:window.innerWidth,\n    height:window.innerHeight,\n    backgroundColor:'#153424',\n    render:{antialias:false,roundPixels:true,powerPreference:'high-performance'},\n    fps:{target:60,smoothStep:true},\n    scene:new GameScene(net),\n    scale:{mode:Phaser.Scale.RESIZE,width:'100%',height:'100%'},\n  });\n}\n\nfunction reserveAmmo(me:any,equipped:string){\n  if(equipped==='pistol'||equipped==='smg')return me?.smallAmmo??0;\n  if(equipped==='rifle')return me?.rifleAmmo??0;\n  if(equipped==='shotgun')return me?.shells??0;\n  return 0;\n}\n\nfunction render(){\n  const s=net.snapshot;\n  if(!s)return;\n  $('codeText').textContent=`#${s.roomCode}`;\n  $('gameCodeText').textContent=`#${s.roomCode}`;\n  if(s.phase==='LOBBY'){\n    lobby.classList.remove('hidden');\n    gameEl.classList.add('hidden');\n    renderLobby(s);\n    return;\n  }\n\n  lobby.classList.add('hidden');\n  gameEl.classList.remove('hidden');\n  if(!game)createGame();\n  const now=performance.now();\n  if(now-lastHudAt<100)return;\n  lastHudAt=now;\n  const me=s.players.find((p)=>p.id===net.sessionId);\n  $('phaseText').textContent=me&&!me.alive?'관전 중 · ← → 대상 변경':s.phase;\n  $('aliveText').textContent=String(s.aliveCount);\n  $('killsText').textContent=String(me?.kills??0);\n  $('zoneText').textContent=String(Math.max(0,Math.ceil(s.zoneTimer)));\n  $('hpText').textContent=String(Math.ceil(me?.hp??0));\n  $('armorText').textContent=String(Math.ceil(me?.armor??0));\n  const equipped=me?.equipped??'fists';\n  $('weaponText').textContent=WEAPONS[equipped as keyof typeof WEAPONS]?.name??MELEE_WEAPONS[equipped as keyof typeof MELEE_WEAPONS]?.name??equipped;\n  $('ammoText').textContent=equipped==='fists'||equipped in MELEE_WEAPONS?'':`${me?.magazine??0} / ${reserveAmmo(me,equipped)}발`;\n  $('itemsText').textContent=`붕대 ${me?.bandages??0} · 구급상자 ${me?.medkits??0}`;\n  if(me?.healingKind){\n    const name=me.healingKind==='medkit'?'구급상자':'붕대';\n    $('healText').textContent=`${name} 회복 중 ${Math.round((me.healingProgress??0)*100)}% · 이동/공격 시 취소`;\n  }else $('healText').textContent='4 자동 회복';\n  if(s.phase==='FINISHED')$('result').classList.remove('hidden');\n}\n\nfunction renderLobby(s:any){\n  $('result').classList.add('hidden');\n  const me=s.players.find((p:any)=>p.id===net.sessionId);\n  const slots=$('slots');\n  slots.innerHTML='';\n  for(let i=0;i<MAX_PLAYERS;i++){\n    const p=s.players[i];\n    const d=document.createElement('div');\n    d.className=`slot ${p?'':'empty'}`;\n    d.innerHTML=p\n      ?`<span class=\"badge\">${p.host?'방장 · ':''}${p.ai?'AI':'PLAYER'}</span><br><b>${escapeText(p.name)}</b> · ${p.ready?'준비':'대기'}`\n      :`빈 슬롯 ${i+1}`;\n    slots.append(d);\n  }\n  $('startBtn').classList.toggle('hidden',!me?.host);\n  $('hostSettings').classList.toggle('hidden',!me?.host);\n  $<HTMLInputElement>('fillAi').checked=s.fillAi;\n  $<HTMLSelectElement>('difficulty').value=s.difficulty;\n  $<HTMLSelectElement>('zoneSpeed').value=s.zoneSpeed;\n}\n\nfunction escapeText(v:string){\n  const d=document.createElement('div');\n  d.textContent=v;\n  return d.innerHTML;\n}\n\ndocument.title=GAME_NAME;\n", "client/src/style.css": ":root{font-family:Pretendard,Inter,system-ui,sans-serif;color:#f6f7f8;background:#071018;--accent:#ffce48;--panel:#121d29;--line:#2a3947}*{box-sizing:border-box}body{margin:0;min-height:100vh;background:radial-gradient(circle at 20% 15%,#18344a 0,transparent 35%),#071018}.hidden{display:none!important}.screen{min-height:100vh}.card{background:rgba(16,29,41,.94);border:1px solid var(--line);border-radius:20px;padding:24px;box-shadow:0 25px 70px #0007}.screen.card{width:min(520px,calc(100% - 28px));min-height:auto;margin:7vh auto}.brand small{color:var(--accent);font-weight:800;letter-spacing:.1em}.brand h1{font-size:58px;margin:5px 0}.brand b{color:var(--accent)}.brand p{color:#aebdca;line-height:1.6}label{display:grid;gap:7px;margin:12px 0;color:#b9c6d0;font-size:13px}input,select,button{font:inherit;border-radius:11px;border:1px solid var(--line);background:#0c1721;color:#fff;padding:12px}button{cursor:pointer;font-weight:800}.primary{background:var(--accent);color:#192027;border-color:var(--accent)}.row{display:flex;gap:10px}.row>*{flex:1}.error{color:#ff7e83;min-height:24px;margin-top:12px}.lobby-layout{width:min(1180px,calc(100% - 28px));margin:auto;padding:28px 0;display:grid;grid-template-columns:1.5fr 1fr;gap:16px}.title-row{display:flex;justify-content:space-between;align-items:center}.slots{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin:18px 0}.slot{padding:13px;border:1px solid var(--line);border-radius:12px;background:#0c1721}.slot.empty{color:#647684}.slot .badge{font-size:11px;color:var(--accent)}.settings{display:flex;gap:12px;align-items:center}.settings label{display:flex;align-items:center}.messages{height:430px;overflow:auto;background:#09131c;border-radius:12px;padding:12px;margin-bottom:12px}.message{margin:7px 0;color:#dce5eb}.message.system{color:#8fa4b4;font-size:13px}.chat-card form,.game-chat{display:flex;gap:8px}.chat-card input,.game-chat input{flex:1}#game{position:relative;overflow:hidden;background:#12271d}#gameCanvas{position:absolute;inset:0}.hud{position:absolute;z-index:10;background:#08131dcc;border:1px solid #ffffff22;border-radius:13px;padding:10px 15px;display:flex;gap:16px;backdrop-filter:blur(5px)}.top{top:12px;left:50%;transform:translateX(-50%)}.bottom{left:12px;bottom:12px;display:block;min-width:280px;line-height:1.7}#killfeed{position:absolute;right:15px;top:70px;z-index:10;text-align:right}.kill{background:#08131dcc;padding:7px 10px;margin:5px;border-radius:8px}.game-messages{position:absolute;z-index:10;left:15px;bottom:120px;width:360px;pointer-events:none}.game-messages .message{background:#08131dcc;padding:7px 10px;border-radius:8px}.game-chat{position:absolute;z-index:20;left:50%;bottom:35px;transform:translateX(-50%);width:min(620px,80%)}.result{position:absolute;z-index:30;inset:0;background:#03090ddd;display:grid;place-content:center;text-align:center}.result h2{font-size:54px;color:var(--accent)}@media(max-width:780px){.lobby-layout{grid-template-columns:1fr}.slots{grid-template-columns:1fr}.settings{display:block}}\n\n.quick-chat{position:absolute;z-index:24;left:50%;bottom:92px;transform:translateX(-50%);display:grid;grid-template-columns:repeat(3,1fr);gap:8px;background:#071018e8;border:1px solid #ffffff22;border-radius:14px;padding:12px}.quick-chat button{white-space:nowrap}.spectating{color:var(--accent);font-weight:900}\n#gameCodeText{color:var(--accent);cursor:pointer;user-select:all}#healText{color:#71f0a9;font-weight:800;min-height:1.3em}#itemsText{color:#c6d3dc}\n", "client/index.html": "<!doctype html><html lang=\"ko\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width,initial-scale=1\"><title>DROP 8</title></head><body>\n<div id=\"app\">\n  <section id=\"home\" class=\"screen card\"><div class=\"brand\"><small>2D REALTIME BATTLE ROYALE</small><h1>DROP <b>8</b></h1><p>친구들과 방 코드로 접속해 비행기에서 낙하하고, 맨손으로 파밍을 시작하세요.</p></div>\n    <label>닉네임<input id=\"nickname\" maxlength=\"16\" placeholder=\"비우면 자동 생성\"></label><label>방 코드<input id=\"roomCode\" maxlength=\"6\" placeholder=\"예: A7BC9K\"></label><label>방 비밀번호<input id=\"password\" maxlength=\"32\" placeholder=\"선택\"></label>\n    <div class=\"row\"><button id=\"createBtn\" class=\"primary\">방 만들기</button><button id=\"joinBtn\">방 참가</button></div><div id=\"homeError\" class=\"error\"></div>\n    <details><summary>조작법</summary><p>WASD 이동 · 마우스 조준 · 좌클릭 공격 · E 획득 · R 재장전 · 1/2/3 무기 · 4 자동 회복 · M 지도 · Enter 채팅 · Space 낙하</p></details>\n  </section>\n  <section id=\"lobby\" class=\"screen hidden\"><div class=\"lobby-layout\"><div class=\"card\"><div class=\"title-row\"><h2>대기실 <span id=\"codeText\"></span></h2><button id=\"copyBtn\">초대 링크 복사</button></div><div id=\"slots\" class=\"slots\"></div><div id=\"hostSettings\" class=\"settings\"><label><input id=\"fillAi\" type=\"checkbox\" checked> 빈자리 AI 충원</label><label>AI <select id=\"difficulty\"><option>easy</option><option selected>normal</option><option>hard</option></select></label><label>자기장 <select id=\"zoneSpeed\"><option>slow</option><option selected>normal</option><option>fast</option></select></label></div><div class=\"row\"><button id=\"readyBtn\" class=\"primary\">준비</button><button id=\"startBtn\">게임 시작</button></div></div>\n    <div class=\"card chat-card\"><h3>로비 채팅</h3><div id=\"lobbyMessages\" class=\"messages\"></div><form id=\"lobbyChat\"><input id=\"lobbyChatInput\" maxlength=\"80\" placeholder=\"메시지\"><button>전송</button></form></div></div></section>\n  <section id=\"game\" class=\"hidden\"><div id=\"gameCanvas\"></div><div id=\"topHud\" class=\"hud top\"><span>방 <b id=\"gameCodeText\">------</b></span><span id=\"phaseText\">PLANE</span><span>생존 <b id=\"aliveText\">8</b></span><span>킬 <b id=\"killsText\">0</b></span><span>자기장 <b id=\"zoneText\">30</b></span></div><div id=\"bottomHud\" class=\"hud bottom\"><div>HP <b id=\"hpText\">100</b> · 조끼 <b id=\"armorText\">0</b></div><div id=\"weaponText\">주먹</div><div id=\"ammoText\"></div><div id=\"itemsText\">붕대 0 · 구급상자 0</div><div id=\"healText\"></div><div id=\"interactText\"></div></div><div id=\"killfeed\"></div><div id=\"gameMessages\" class=\"game-messages\"></div><form id=\"gameChat\" class=\"game-chat hidden\"><input id=\"gameChatInput\" maxlength=\"80\" placeholder=\"근거리 채팅\"><button>전송</button></form><div id=\"quickChat\" class=\"quick-chat hidden\"><button data-msg=\"무기 없다!\">무기 없다!</button><button data-msg=\"싸우지 말자!\">싸우지 말자!</button><button data-msg=\"여기 누구 있다!\">여기 누구 있다!</button><button data-msg=\"도망가자!\">도망가자!</button><button data-msg=\"나와라!\">나와라!</button><button data-msg=\"ㅋㅋㅋㅋ\">ㅋㅋㅋㅋ</button></div><div id=\"result\" class=\"result hidden\"><h2 id=\"resultTitle\"></h2><p id=\"resultStats\"></p><button id=\"rematchBtn\" class=\"primary\">로비로 돌아가기</button></div></section>\n</div><script type=\"module\" src=\"/src/main.ts\"></script></body></html>\n", "server/tests/room.test.ts": "import { afterAll, beforeAll, beforeEach, describe, expect, it } from 'vitest';\nimport { boot, type ColyseusTestServer } from '@colyseus/testing';\nimport app from '../src/app.config.js';\nimport type { Drop8State } from '../src/rooms/schema.js';\n\ndescribe('DROP 8 room integration', () => {\n  let server: ColyseusTestServer<typeof app>;\n\n  beforeAll(async () => {\n    server = await boot(app);\n  });\n\n  afterAll(async () => {\n    await server.shutdown();\n  });\n\n  beforeEach(async () => {\n    await server.cleanup();\n  });\n\n  const quiet = <T extends { onMessage: (type: string, callback: () => void) => unknown }>(client: T): T => {\n    for (const type of ['chat', 'killfeed', 'result', 'error']) {\n      client.onMessage(type, () => undefined);\n    }\n    return client;\n  };\n\n  it('creates a room and synchronizes two clients', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: false });\n    const first = quiet(await server.connectTo(room, { nickname: 'A' }));\n    const second = quiet(await server.connectTo(room, { nickname: 'B' }));\n    await room.waitForNextPatch();\n\n    expect(first.state.players.size).toBe(2);\n    expect(second.state.roomCode).toHaveLength(6);\n  });\n\n  it('fills empty slots with AI after every human is ready', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: true });\n    const client = quiet(await server.connectTo(room, { nickname: 'A' }));\n\n    client.send('ready');\n    await new Promise((resolve) => setTimeout(resolve, 80));\n    client.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 150));\n\n    expect(room.state.players.size).toBe(8);\n    expect(['PLANE', 'DROP']).toContain(room.state.phase);\n  });\n\n  it('accepts eight human clients without adding AI', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: false });\n    const clients = [];\n\n    for (let index = 0; index < 8; index += 1) {\n      clients.push(quiet(await server.connectTo(room, { nickname: `P${index + 1}` })));\n    }\n    for (const client of clients) {\n      client.send('ready');\n    }\n    await new Promise((resolve) => setTimeout(resolve, 160));\n    clients[0]?.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 180));\n\n    expect(room.state.players.size).toBe(8);\n    expect([...room.state.players.values()].filter((player) => player.ai)).toHaveLength(0);\n    expect(['PLANE', 'DROP']).toContain(room.state.phase);\n  });\n\n  it('moves a client through server-authoritative input', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: false });\n    const client = quiet(await server.connectTo(room, { nickname: 'Mover' }));\n    client.send('ready');\n    await new Promise((resolve) => setTimeout(resolve, 60));\n    client.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 80));\n    client.send('jump');\n    await new Promise((resolve) => setTimeout(resolve, 80));\n\n    const player = room.state.players.get(client.sessionId);\n    expect(player).toBeDefined();\n    player!.altitude = 0;\n    player!.phase = 'landed';\n    const beforeX = player!.x;\n    client.send('input', { x: 1, y: 0, angle: 0, seq: 1 });\n    await new Promise((resolve) => setTimeout(resolve, 150));\n\n    expect(player!.x).toBeGreaterThan(beforeX);\n  });\n\n  it('moves landed AI continuously between decision ticks', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: true });\n    const client = quiet(await server.connectTo(room, { nickname: 'Host' }));\n    client.send('ready');\n    await new Promise((resolve) => setTimeout(resolve, 60));\n    client.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 120));\n\n    const ai = [...room.state.players.values()].find((player) => player.ai);\n    expect(ai).toBeDefined();\n    ai!.phase = 'landed';\n    ai!.x = 2700;\n    ai!.y = 2000;\n    const before = { x: ai!.x, y: ai!.y };\n    await new Promise((resolve) => setTimeout(resolve, 520));\n\n    expect(Math.hypot(ai!.x - before.x, ai!.y - before.y)).toBeGreaterThan(8);\n  });\n\n  it('applies hit state and knockback for a fist attack', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: false });\n    const attacker = quiet(await server.connectTo(room, { nickname: 'Attacker' }));\n    const victim = quiet(await server.connectTo(room, { nickname: 'Victim' }));\n    attacker.send('ready');\n    victim.send('ready');\n    await new Promise((resolve) => setTimeout(resolve, 70));\n    attacker.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 100));\n\n    const a = room.state.players.get(attacker.sessionId)!;\n    const v = room.state.players.get(victim.sessionId)!;\n    a.phase = 'landed';\n    v.phase = 'landed';\n    a.x = 2700;\n    a.y = 2000;\n    v.x = 2750;\n    v.y = 2000;\n    const beforeX = v.x;\n    attacker.send('input', { x: 0, y: 0, angle: 0, seq: 1 });\n    await new Promise((resolve) => setTimeout(resolve, 60));\n    attacker.send('melee');\n    await new Promise((resolve) => setTimeout(resolve, 180));\n\n    expect(v.hitSeq).toBeGreaterThan(0);\n    expect(v.lastHitDamage).toBeGreaterThan(0);\n    expect(v.x).toBeGreaterThan(beforeX);\n  });\n\n\n  it('keeps a healing item until completion and restores health', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: false });\n    const client = quiet(await server.connectTo(room, { nickname: 'Healer' }));\n    client.send('ready');\n    await new Promise((resolve) => setTimeout(resolve, 60));\n    client.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 80));\n\n    const player = room.state.players.get(client.sessionId)!;\n    player.phase = 'landed';\n    player.x = 2048;\n    player.y = 2048;\n    player.hp = 50;\n    player.bandages = 1;\n    client.send('heal', { kind: 'auto' });\n    await new Promise((resolve) => setTimeout(resolve, 140));\n\n    expect(player.healingKind).toBe('bandage');\n    expect(player.bandages).toBe(1);\n    expect(player.healingProgress).toBeGreaterThan(0);\n\n    await new Promise((resolve) => setTimeout(resolve, 2050));\n    expect(player.hp).toBe(75);\n    expect(player.bandages).toBe(0);\n    expect(player.healingKind).toBe('');\n  });\n\n  it('preserves a separate magazine for each firearm', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: false });\n    const client = quiet(await server.connectTo(room, { nickname: 'Switcher' }));\n    const player = room.state.players.get(client.sessionId)!;\n    player.primary = 'rifle';\n    player.secondary = 'pistol';\n    player.rifleMagazine = 5;\n    player.pistolMagazine = 11;\n\n    client.send('switch', { slot: 1 });\n    await new Promise((resolve) => setTimeout(resolve, 70));\n    expect(player.equipped).toBe('rifle');\n    expect(player.magazine).toBe(5);\n\n    client.send('switch', { slot: 2 });\n    await new Promise((resolve) => setTimeout(resolve, 70));\n    expect(player.equipped).toBe('pistol');\n    expect(player.magazine).toBe(11);\n  });\n\n  it('lets AI choose a suitable loaded weapon for a distant target', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: true });\n    const client = quiet(await server.connectTo(room, { nickname: 'Target' }));\n    client.send('ready');\n    await new Promise((resolve) => setTimeout(resolve, 60));\n    client.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 120));\n\n    const human = room.state.players.get(client.sessionId)!;\n    const ai = [...room.state.players.values()].find((player) => player.ai)!;\n    human.phase = 'landed';\n    human.x = 3350;\n    human.y = 2000;\n    ai.phase = 'landed';\n    ai.x = 2700;\n    ai.y = 2000;\n    ai.primary = 'rifle';\n    ai.secondary = 'pistol';\n    ai.rifleMagazine = 8;\n    ai.pistolMagazine = 12;\n    ai.equipped = 'pistol';\n    ai.magazine = 12;\n\n    await new Promise((resolve) => setTimeout(resolve, 3400));\n    expect(ai.equipped).toBe('rifle');\n    expect(ai.aiState).toMatch(/ENGAGE|REPOSITION|RETREAT/);\n  });\n\n  it('allows a safe low-health AI to use a bandage', async () => {\n    const room = await server.createRoom<Drop8State>('drop8', { fillAi: true });\n    const client = quiet(await server.connectTo(room, { nickname: 'FarAway' }));\n    client.send('ready');\n    await new Promise((resolve) => setTimeout(resolve, 60));\n    client.send('start');\n    await new Promise((resolve) => setTimeout(resolve, 120));\n\n    const human = room.state.players.get(client.sessionId)!;\n    const ai = [...room.state.players.values()].find((player) => player.ai)!;\n    human.phase = 'landed';\n    human.x = 3900;\n    human.y = 3900;\n    ai.phase = 'landed';\n    ai.x = 2700;\n    ai.y = 2000;\n    ai.hp = 30;\n    ai.bandages = 1;\n\n    await new Promise((resolve) => setTimeout(resolve, 5350));\n    expect(ai.hp).toBeGreaterThanOrEqual(55);\n    expect(ai.bandages).toBe(0);\n    expect(ai.healingKind).toBe('');\n  });\n\n});\n"};
const required=["server/src/rooms/schema.ts", "server/src/rooms/Drop8Room.ts", "client/src/GameScene.ts", "client/src/main.ts", "client/src/style.css", "client/index.html", "server/tests/room.test.ts"];

for(const rel of required){
  const target=path.join(root,rel);
  if(!fs.existsSync(target)){
    console.error(`필수 파일 없음: ${rel}`);
    process.exit(1);
  }
}

const roomSource=fs.readFileSync(path.join(root,'server/src/rooms/Drop8Room.ts'),'utf8');
const schemaSource=fs.readFileSync(path.join(root,'server/src/rooms/schema.ts'),'utf8');
if(!roomSource.includes('private updateAi')||!schemaSource.includes('hitSeq')){
  console.error('refactor_002 적용본을 찾지 못했습니다. 먼저 002 패치를 적용하세요.');
  process.exit(1);
}

const already=Object.entries(files).every(([rel,content])=>fs.readFileSync(path.join(root,rel),'utf8')===content);
if(already){
  console.log('refactor_003는 이미 적용되어 있습니다.');
  process.exit(0);
}

fs.mkdirSync(backupRoot,{recursive:true});
for(const [rel,content] of Object.entries(files)){
  const target=path.join(root,rel);
  const backup=path.join(backupRoot,rel);
  fs.mkdirSync(path.dirname(backup),{recursive:true});
  fs.copyFileSync(target,backup);
  fs.writeFileSync(target,content,'utf8');
  console.log(`수정: ${rel}`);
}

const notesPath=path.join(root,'docs','PATCH_NOTES.md');
if(fs.existsSync(notesPath)){
  const current=fs.readFileSync(notesPath,'utf8');
  const marker='refactor_003 — 회복, AI 장비 판단, 인게임 방 코드';
  if(!current.includes(marker)){
    fs.appendFileSync(notesPath,`
## refactor_003 — 회복, AI 장비 판단, 인게임 방 코드

- 4번 키를 자동 회복으로 변경하고 붕대/구급상자를 체력 손실에 따라 선택
- 회복 아이템은 완료 시점에만 차감하며 이동·공격·피격·무기 교체 시 취소
- 회복 종류와 진행률을 서버 상태 및 HUD에 표시
- 총기별 탄창을 분리해 무기 교체 후 탄창이 섞이는 문제 수정
- AI가 거리·탄약·탄창을 고려해 무기를 선택하고 빈 탄창을 재장전
- AI가 체력이 낮고 안전할 때 회복약 사용
- AI 파밍을 무기 업그레이드, 필요한 탄약, 방어구, 회복약 점수제로 변경
- 최근 총소리 조사, 마지막 목격 위치 기억, 저체력 후퇴 추가
- 건물 안팎 목표에 문 바깥/안쪽 경유점을 사용하는 이동 경로 추가
- 게임 중 상단 HUD에 방 코드를 항상 표시하고 클릭 시 초대 링크 복사
- 회복, 총기별 탄창, AI 무기 선택, AI 회복 통합 테스트 추가
`,'utf8');
  }
}

console.log('DROP 8 refactor_003 적용 완료');
console.log(`백업 위치: ${backupRoot}`);
console.log('다음 실행: pnpm typecheck && pnpm lint && pnpm test && pnpm dev:lan');
